// Firebase SDK loaded from CDN in the HTML — accessed via window.firebase globals
// We lazily initialise once and reuse the same app instance.
let _fbApp = null;
let _fbAuth = null;
let _fbDb = null;

function getFirebase() {
  if (_fbApp) return { app: _fbApp, auth: _fbAuth, db: _fbDb };
  try {
    const { initializeApp } = window.firebase_app || {};
    const { getAuth } = window.firebase_auth || {};
    const { getFirestore } = window.firebase_firestore || {};
    if (!initializeApp) throw new Error("Firebase SDK not loaded");
    _fbApp  = initializeApp(FIREBASE_CONFIG);
    _fbAuth = getAuth(_fbApp);
    _fbDb   = getFirestore(_fbApp);
    return { app: _fbApp, auth: _fbAuth, db: _fbDb };
  } catch (e) {
    console.error("Firebase init error:", e);
    return null;
  }
}

// ---------------------------------------------------------------------------
// Firestore helpers
// ---------------------------------------------------------------------------
async function fbGet(collection, docId) {
  try {
    const fb = getFirebase();
    if (!fb) return null;
    const { doc, getDoc } = window.firebase_firestore;
    const snap = await getDoc(doc(fb.db, collection, docId));
    return snap.exists() ? snap.data() : null;
  } catch (e) {
    console.warn("fbGet error:", e);
    return null;
  }
}

async function fbSet(collection, docId, data) {
  try {
    const fb = getFirebase();
    if (!fb) return false;
    const { doc, setDoc } = window.firebase_firestore;
    await setDoc(doc(fb.db, collection, docId), data, { merge: true });
    return true;
  } catch (e) {
    console.warn("fbSet error:", e);
    return false;
  }
}

async function fbGetAll(collection) {
  try {
    const fb = getFirebase();
    if (!fb) return [];
    const { collection: col, getDocs } = window.firebase_firestore;
    const snap = await getDocs(col(fb.db, collection));
    return snap.docs.map(d => ({ id: d.id, ...d.data() }));
  } catch (e) {
    console.warn("fbGetAll error:", e);
    return [];
  }
}

async function fbDelete(collection, docId) {
  try {
    const fb = getFirebase();
    if (!fb) return false;
    const { doc, deleteDoc } = window.firebase_firestore;
    await deleteDoc(doc(fb.db, collection, docId));
    return true;
  } catch (e) {
    console.warn("fbDelete error:", e);
    return false;
  }
}

// ---------------------------------------------------------------------------
// localStorage fallback (keeps things working while Firebase loads)
// ---------------------------------------------------------------------------
const _memStore = new Map();

function lsSet(key, value) {
  const serialized = typeof value === "string" ? value : JSON.stringify(value);
  _memStore.set(key, serialized);
  try { localStorage.setItem("mha_" + key, serialized); } catch (e) {}
}

function lsGet(key) {
  try {
    const v = localStorage.getItem("mha_" + key);
    if (v !== null) { try { return JSON.parse(v); } catch { return v; } }
  } catch (e) {}
  const v = _memStore.get(key);
  if (v === undefined) return null;
  try { return JSON.parse(v); } catch { return v; }
}

function lsDel(key) {
  _memStore.delete(key);
  try { localStorage.removeItem("mha_" + key); } catch (e) {}
}

// Simple hash for password (Firebase Auth handles real security)
function hashPassword(password) {
  const SALT = "MedinaHomestays2026";
  const combined = password + SALT + password.split("").reverse().join("");
  try { return Promise.resolve("h1_" + btoa(unescape(encodeURIComponent(combined)))); }
  catch (e) {
    let h = 5381;
    for (let i = 0; i < combined.length; i++) { h = ((h << 5) + h) ^ combined.charCodeAt(i); h = h >>> 0; }
    return Promise.resolve("h2_" + h.toString(36));
  }
}

function normalizeEmail(email) { return email.trim().toLowerCase(); }
function generateHostId() { return `host_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`; }

// Legacy window.storage helpers (kept for admin panel backward compat)
function withTimeout(promise, ms = 3000) {
  return Promise.race([promise, new Promise((resolve) => setTimeout(() => resolve(null), ms))]).catch(() => null);
}
async function readDoc(path, fallbackKey) {
  try {
    const result = await withTimeout(window.storage?.get(fallbackKey, true));
    return result?.value ? JSON.parse(result.value) : null;
  } catch (e) { return null; }
}
async function writeDoc(path, data, fallbackKey) {
  try { await withTimeout(window.storage?.set(fallbackKey, JSON.stringify(data), true)); } catch (e) {}
  return true;
}
async function readCollection(prefix, keyPrefix) {
  try {
    const result = await withTimeout(window.storage?.list(keyPrefix, true));
    if (!result?.keys?.length) return {};
    const entries = await Promise.all(
      result.keys.map(async (k) => {
        const key = k.startsWith(keyPrefix) ? k : keyPrefix + k;
        const r = await withTimeout(window.storage?.get(key, true));
        if (!r?.value) return null;
        try { return [k.replace(keyPrefix, ""), JSON.parse(r.value)]; } catch { return null; }
      })
    );
    return Object.fromEntries(entries.filter(Boolean));
  } catch (e) { return {}; }
}

// ---------------------------------------------------------------------------
// Host data hook — /hosts/{hostId}
// ---------------------------------------------------------------------------
const DEMO_HOST_ID = "demo-host";

const DEFAULT_HOST = {
  id: DEMO_HOST_ID,
  name: "عبدالله الحربي",
  nameEn: "Abdullah Al-Harbi",
  email: "abdullah@example.com",
  phone: "",
  district: "",
  city: "المدينة المنورة",
  tier: "basic",
  status: "active", // active | suspended | revoked
  points: 140,
  rating: 4.6,
  guestsHosted: 7,
  completedLessons: ["1-1", "1-2"],
  quizScores: {},
  certificates: [],
  joinedAt: "2026-04-01",
};

function useHostData(hostId = DEMO_HOST_ID) {
  const [host, setHost] = useState({ ...DEFAULT_HOST, id: hostId });
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    if (!hostId) return;
    setLoaded(false);

    // 1. Load from localStorage instantly
    const cached = lsGet(`host:${hostId}`);
    if (cached) { setHost({ ...DEFAULT_HOST, ...cached, id: hostId }); setLoaded(true); }

    // 2. Sync from Firestore in background
    (async () => {
      const data = await fbGet("hosts", hostId);
      if (data) {
        const merged = { ...DEFAULT_HOST, ...data, id: hostId };
        setHost(merged);
        lsSet(`host:${hostId}`, merged);
      } else if (!cached) {
        setHost({ ...DEFAULT_HOST, id: hostId });
      }
      setLoaded(true);
    })();
  }, [hostId]);

  const persist = (next) => {
    setHost(next);
    lsSet(`host:${hostId}`, next);
    fbSet("hosts", hostId, next).catch(() => {});
  };

  const completeLesson = (lessonId) => {
    if (host.completedLessons.includes(lessonId)) return;
    persist({ ...host, completedLessons: [...host.completedLessons, lessonId], points: host.points + 10 });
  };

  const recordQuiz = (moduleId, score, passScore) => {
    const quizScores = { ...host.quizScores, [moduleId]: score };
    let { points, certificates } = host;
    if (score >= passScore && !certificates.includes(`module-${moduleId}`)) {
      points += 50;
      certificates = [...certificates, `module-${moduleId}`];
    }
    persist({ ...host, quizScores, certificates, points });
  };

  return { host, loaded, completeLesson, recordQuiz, persist };
}

// ---------------------------------------------------------------------------
// Auth hook — Firebase Authentication + Firestore for host profiles
// ---------------------------------------------------------------------------
function useHostAuth() {
  const [hostId, setHostId] = useState(null);
  const [checkingSession, setCheckingSession] = useState(true);
  const [authBusy, setAuthBusy] = useState(false);
  const [authError, setAuthError] = useState("");

  // Listen to Firebase Auth state changes
  useEffect(() => {
    const fb = getFirebase();
    if (!fb) {
      // Firebase not available — fallback to localStorage
      const saved = lsGet("session");
      if (saved) setHostId(saved);
      setCheckingSession(false);
      return;
    }
    const { onAuthStateChanged } = window.firebase_auth;
    const unsub = onAuthStateChanged(fb.auth, async (user) => {
      if (user) {
        // Get hostId from Firestore user profile
        const profile = await fbGet("hosts", user.uid);
        const hId = profile?.id || user.uid;
        setHostId(hId);
        lsSet("session", hId);
      } else {
        setHostId(null);
        lsDel("session");
      }
      setCheckingSession(false);
    });
    return () => unsub();
  }, []);

  const clearError = () => setAuthError("");

  const signup = async ({ name, email, phone, district, password }) => {
    setAuthBusy(true);
    setAuthError("");
    try {
      const normalized = normalizeEmail(email);
      if (!name.trim() || !normalized || !phone.trim() || !district.trim() || !password) {
        setAuthError("يرجى تعبئة جميع الحقول المطلوبة."); return false;
      }
      if (!normalized.includes("@") || !normalized.includes(".")) {
        setAuthError("البريد الإلكتروني غير صحيح."); return false;
      }
      if (password.length < 6) {
        setAuthError("كلمة المرور يجب أن تكون 6 أحرف على الأقل."); return false;
      }

      const fb = getFirebase();
      if (fb) {
        // Firebase Auth signup
        const { createUserWithEmailAndPassword, updateProfile } = window.firebase_auth;
        const cred = await createUserWithEmailAndPassword(fb.auth, normalized, password);
        const user = cred.user;
        await updateProfile(user, { displayName: name.trim() });

        // Save profile to Firestore
        const newHost = {
          ...DEFAULT_HOST,
          id: user.uid,
          name: name.trim(),
          email: normalized,
          phone: phone.trim(),
          district: district.trim(),
          city: "المدينة المنورة",
          tier: "basic",
          status: "active",
          points: 0,
          rating: 0,
          guestsHosted: 0,
          completedLessons: [],
          quizScores: {},
          certificates: [],
          joinedAt: new Date().toISOString().slice(0, 10),
        };
        await fbSet("hosts", user.uid, newHost);
        lsSet(`host:${user.uid}`, newHost);
        // onAuthStateChanged will set hostId automatically
        return true;
      } else {
        // Fallback: localStorage only
        const existing = lsGet(`auth:${normalized}`);
        if (existing) { setAuthError("يوجد حساب مسجّل بهذا البريد مسبقًا."); return false; }
        const newHostId = generateHostId();
        const passwordHash = await hashPassword(password);
        lsSet(`auth:${normalized}`, { hostId: newHostId, email: normalized, passwordHash });
        const newHost = { ...DEFAULT_HOST, id: newHostId, name: name.trim(), email: normalized, phone: phone.trim(), district: district.trim(), city: "المدينة المنورة", tier: "basic", status: "active", points: 0, rating: 0, guestsHosted: 0, completedLessons: [], quizScores: {}, certificates: [], joinedAt: new Date().toISOString().slice(0, 10) };
        lsSet(`host:${newHostId}`, newHost);
        lsSet("session", newHostId);
        setHostId(newHostId);
        return true;
      }
    } catch (e) {
      console.error("signup error", e);
      if (e.code === "auth/email-already-in-use") setAuthError("يوجد حساب مسجّل بهذا البريد الإلكتروني مسبقًا.");
      else if (e.code === "auth/weak-password") setAuthError("كلمة المرور ضعيفة جداً. يجب أن تكون 6 أحرف على الأقل.");
      else if (e.code === "auth/network-request-failed") setAuthError("خطأ في الاتصال. تحقق من الإنترنت.");
      else setAuthError("حدث خطأ غير متوقع. يرجى المحاولة مرة أخرى.");
      return false;
    } finally {
      setAuthBusy(false);
    }
  };

  const login = async ({ email, password }) => {
    setAuthBusy(true);
    setAuthError("");
    try {
      const normalized = normalizeEmail(email);
      if (!normalized || !password) { setAuthError("يرجى إدخال البريد وكلمة المرور."); return false; }

      const fb = getFirebase();
      if (fb) {
        const { signInWithEmailAndPassword } = window.firebase_auth;
        await signInWithEmailAndPassword(fb.auth, normalized, password);
        // onAuthStateChanged will set hostId
        return true;
      } else {
        // Fallback
        const authRecord = lsGet(`auth:${normalized}`);
        if (!authRecord) { setAuthError("لا يوجد حساب مسجّل بهذا البريد."); return false; }
        const passwordHash = await hashPassword(password);
        if (passwordHash !== authRecord.passwordHash) { setAuthError("كلمة المرور غير صحيحة."); return false; }
        lsSet("session", authRecord.hostId);
        setHostId(authRecord.hostId);
        return true;
      }
    } catch (e) {
      if (e.code === "auth/user-not-found" || e.code === "auth/invalid-credential") setAuthError("البريد الإلكتروني أو كلمة المرور غير صحيحة.");
      else if (e.code === "auth/wrong-password") setAuthError("كلمة المرور غير صحيحة.");
      else if (e.code === "auth/too-many-requests") setAuthError("تم تجاوز عدد المحاولات. يرجى المحاولة لاحقاً.");
      else if (e.code === "auth/network-request-failed") setAuthError("خطأ في الاتصال. تحقق من الإنترنت.");
      else setAuthError("حدث خطأ. يرجى المحاولة مرة أخرى.");
      return false;
    } finally {
      setAuthBusy(false);
    }
  };

  const logout = () => {
    const fb = getFirebase();
    if (fb) { const { signOut } = window.firebase_auth; signOut(fb.auth).catch(() => {}); }
    lsDel("session");
    setHostId(null);
  };

  return { hostId, checkingSession, authBusy, authError, clearError, signup, login, logout };
}

// ---------------------------------------------------------------------------
// Content data hook — /modules/{id} and /quizzes/{id} (CMS-managed)
// ---------------------------------------------------------------------------
function useContentData() {
  const [modules, setModules] = useState(SEED_MODULES);
  const [quizzes, setQuizzes] = useState(SEED_QUIZZES);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        const modData = await readCollection("modules", "modules:");
        const quizData = await readCollection("quizzes", "quizzes:");

        if (Object.keys(modData).length > 0) {
          const merged = Object.values(modData)
            .filter((m) => !m.deleted && m.lessons)
            .map((m) => ({ ...m, icon: SEED_MODULES.find((sm) => sm.id === m.id)?.icon || BookOpen }))
            .sort((a, b) => a.id - b.id);
          if (merged.length > 0) setModules(merged);
        } else {
          // Seed storage in background — don't await, use seed data immediately
          Promise.all(SEED_MODULES.map(({ icon, ...mod }) =>
            writeDoc(`modules/${mod.id}`, mod, `modules:${mod.id}`)
          )).catch(() => {});
        }

        if (Object.keys(quizData).length > 0) {
          const merged = {};
          Object.entries(quizData).forEach(([k, v]) => { merged[Number(k)] = v; });
          setQuizzes(merged);
        } else {
          // Seed quizzes in background too
          Promise.all(Object.entries(SEED_QUIZZES).map(([id, quiz]) =>
            writeDoc(`quizzes/${id}`, quiz, `quizzes:${id}`)
          )).catch(() => {});
        }
      } catch (e) {
        // ignore — seed data already set as default state
      } finally {
        setLoaded(true);
      }
    })();
  }, []);

  const saveModule = async (mod) => {
    const { icon, ...serializable } = mod;
    setModules((prev) => {
      const exists = prev.some((m) => m.id === mod.id);
      const next = exists
        ? prev.map((m) => (m.id === mod.id ? { ...mod, icon: m.icon || BookOpen } : m))
        : [...prev, { ...mod, icon: BookOpen }].sort((a, b) => a.id - b.id);
      return next;
    });
    await writeDoc(`modules/${mod.id}`, serializable, `modules:${mod.id}`);
  };

  const deleteModule = async (moduleId) => {
    setModules((prev) => prev.filter((m) => m.id !== moduleId));
    await writeDoc(`modules/${moduleId}`, { deleted: true }, `modules:${moduleId}`);
  };

  const saveQuiz = async (moduleId, quiz) => {
    setQuizzes((prev) => ({ ...prev, [moduleId]: quiz }));
    await writeDoc(`quizzes/${moduleId}`, quiz, `quizzes:${moduleId}`);
  };

  return { modules, quizzes, loaded, saveModule, deleteModule, saveQuiz };
}

// ---------------------------------------------------------------------------
// All-hosts hook (admin) — reads /hosts collection
// ---------------------------------------------------------------------------
function useAllHosts() {
  const [hosts, setHosts] = useState([]);
  const [loaded, setLoaded] = useState(false);

  const reload = async () => {
    setLoaded(false);
    try {
      // Try Firestore first
      const fbHosts = await fbGetAll("hosts");
      if (fbHosts.length > 0) {
        setHosts(fbHosts.map(h => ({ ...DEFAULT_HOST, ...h })));
      } else {
        // Fallback to window.storage
        const data = await readCollection("hosts", "hosts:");
        const list = Object.entries(data).map(([id, v]) => ({ ...DEFAULT_HOST, ...v, id }));
        setHosts(list.length > 0 ? list : [{ ...DEFAULT_HOST }]);
      }
    } catch (e) {
      setHosts([{ ...DEFAULT_HOST }]);
    } finally {
      setLoaded(true);
    }
  };

  useEffect(() => { reload(); }, []);

  const hostsRef = useRef(hosts);
  hostsRef.current = hosts;

  const updateHost = async (hostId, patch) => {
    const current = hostsRef.current.find((h) => h.id === hostId) || { ...DEFAULT_HOST, id: hostId };
    const next = { ...current, ...patch };
    setHosts((prev) => {
      const exists = prev.some((h) => h.id === hostId);
      return exists ? prev.map((h) => (h.id === hostId ? next : h)) : [...prev, next];
    });
    hostsRef.current = hostsRef.current.some((h) => h.id === hostId)
      ? hostsRef.current.map((h) => (h.id === hostId ? next : h))
      : [...hostsRef.current, next];
    await fbSet("hosts", hostId, next);
    lsSet(`host:${hostId}`, next);
  };

  return { hosts, loaded, reload, updateHost };
}

// ---------------------------------------------------------------------------
// Helper calculations
// ---------------------------------------------------------------------------
function moduleProgress(module, completedLessons) {
  if (!module.lessons || module.lessons.length === 0) return 0;
  const done = module.lessons.filter((l) => completedLessons.includes(l.id)).length;
  return Math.round((done / module.lessons.length) * 100);
}

function tierProgress(tier, completedLessons, allModules) {
  const mods = allModules.filter((m) => tier.modules.includes(m.id));
  if (mods.length === 0) return 0;
  const totalLessons = mods.reduce((s, m) => s + m.lessons.length, 0);
  const doneLessons = mods.reduce(
    (s, m) => s + m.lessons.filter((l) => completedLessons.includes(l.id)).length,
    0
  );
  return totalLessons === 0 ? 0 : Math.round((doneLessons / totalLessons) * 100);
}

// ---------------------------------------------------------------------------
// Shared UI bits
// ---------------------------------------------------------------------------
function ProgressBar({ value, color = COLORS.teal, height = 8 }) {
  const safeValue = Number.isFinite(value) ? Math.min(100, Math.max(0, value)) : 0;
  return (
    <div style={{ background: COLORS.line, borderRadius: 999, height, width: "100%", overflow: "hidden" }}>
      <div
        style={{
          width: `${safeValue}%`,
          height: "100%",
          background: color,
          borderRadius: 999,
          transition: "width 0.5s ease",
        }}
      />
    </div>
  );
}

function Pill({ children, color, bg }) {
  return (
    <span
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: 4,
        fontSize: 12,
        fontWeight: 600,
        padding: "3px 10px",
        borderRadius: 999,
        color: color,
        background: bg,
        whiteSpace: "nowrap",
      }}
    >
      {children}
    </span>
  );
}

