// ---------------------------------------------------------------------------
// Lesson Reader — mandatory text-reading flow (replaces video lessons)
// ---------------------------------------------------------------------------
const WORDS_PER_MINUTE = 130;

function estimateReadSeconds(body) {
  if (!body || body.length === 0) return 20;
  const wordCount = body.join(" ").split(/\s+/).filter(Boolean).length;
  const minutes = wordCount / WORDS_PER_MINUTE;
  return Math.max(20, Math.round(minutes * 60));
}

// ---------------------------------------------------------------------------
// Audio player for lesson narration
// ---------------------------------------------------------------------------
function LessonAudioPlayer({ audioUrl }) {
  const audioRef = useRef(null);
  const [playing, setPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrent] = useState(0);

  const toggle = () => {
    const a = audioRef.current;
    if (!a) return;
    if (playing) { a.pause(); setPlaying(false); }
    else { a.play(); setPlaying(true); }
  };

  const onTimeUpdate = () => {
    const a = audioRef.current;
    if (!a) return;
    setCurrent(a.currentTime);
    setProgress(a.duration ? (a.currentTime / a.duration) * 100 : 0);
  };

  const onLoaded = () => { if (audioRef.current) setDuration(audioRef.current.duration); };
  const onEnded = () => setPlaying(false);

  const seek = (e) => {
    const a = audioRef.current;
    if (!a || !a.duration) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const ratio = (e.clientX - rect.left) / rect.width;
    a.currentTime = ratio * a.duration;
  };

  const fmt = (s) => {
    if (!s || isNaN(s)) return "0:00";
    const m = Math.floor(s / 60), sec = Math.floor(s % 60);
    return `${m}:${String(sec).padStart(2, "0")}`;
  };

  return (
    <div style={{
      background: `linear-gradient(135deg, ${COLORS.teal}0F, ${COLORS.teal}06)`,
      border: `1px solid ${COLORS.teal}30`,
      borderRadius: 14, padding: "12px 14px",
      display: "flex", flexDirection: "column", gap: 10,
    }}>
      <audio ref={audioRef} src={audioUrl} onTimeUpdate={onTimeUpdate} onLoadedMetadata={onLoaded} onEnded={onEnded} preload="metadata" />

      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        {/* Play / Pause */}
        <button
          onClick={toggle}
          style={{
            width: 40, height: 40, borderRadius: 12, border: "none",
            background: COLORS.teal, cursor: "pointer", flexShrink: 0,
            display: "flex", alignItems: "center", justifyContent: "center",
            boxShadow: `0 2px 12px ${COLORS.teal}40`,
          }}
        >
          {playing
            ? <span style={{ display: "flex", gap: 3 }}><span style={{ width: 3, height: 14, background: "#fff", borderRadius: 2 }}/><span style={{ width: 3, height: 14, background: "#fff", borderRadius: 2 }}/></span>
            : <span style={{ display: "inline-block", width: 0, height: 0, borderTop: "7px solid transparent", borderBottom: "7px solid transparent", borderLeft: "12px solid #fff", marginRight: -2 }}/>
          }
        </button>

        <div style={{ flex: 1 }}>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 10, color: COLORS.inkSoft, marginBottom: 5 }}>
            <span style={{ color: COLORS.teal, fontWeight: 700, fontSize: 10.5 }}>🎧 استمع للدرس</span>
            <span>{fmt(currentTime)} / {fmt(duration)}</span>
          </div>
          {/* Progress bar clickable */}
          <div
            onClick={seek}
            style={{ height: 5, background: COLORS.line, borderRadius: 999, cursor: "pointer", position: "relative" }}
          >
            <div style={{ width: `${progress}%`, height: "100%", background: COLORS.teal, borderRadius: 999, transition: "width .1s" }}/>
          </div>
        </div>
      </div>
    </div>
  );
}

function LessonReader({ module, lesson, lessonIndex, onComplete, onBack, onNextLesson, onPrevLesson, onGoHome }) {
  const requiredSeconds = useMemo(() => estimateReadSeconds(lesson.body), [lesson]);
  const [elapsed, setElapsed] = useState(0);
  const [reachedEnd, setReachedEnd] = useState(false);
  const [confirmed, setConfirmed] = useState(false);
  const scrollRef = useRef(null);

  useEffect(() => {
    setElapsed(0);
    setReachedEnd(false);
    setConfirmed(false);
  }, [lesson.id]);

  useEffect(() => {
    const el = scrollRef.current;
    if (!el) return;
    const needsScroll = el.scrollHeight - el.clientHeight > 4;
    if (!needsScroll) setReachedEnd(true);
  }, [lesson.id]);

  useEffect(() => {
    if (elapsed >= requiredSeconds) return;
    const t = setInterval(() => setElapsed((e) => Math.min(requiredSeconds, e + 1)), 1000);
    return () => clearInterval(t);
  }, [elapsed, requiredSeconds]);

  const handleScroll = () => {
    const el = scrollRef.current;
    if (!el) return;
    if (el.scrollHeight - el.scrollTop - el.clientHeight < 24) setReachedEnd(true);
  };

  const timeReady = elapsed >= requiredSeconds;
  const canConfirm = timeReady && reachedEnd;
  const timePct = Math.round((elapsed / requiredSeconds) * 100);
  const minutesLabel = Math.max(1, Math.round(requiredSeconds / 60));
  const isFirst = lessonIndex === 0;
  const isLast = lessonIndex === module.lessons.length - 1;

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>

      {/* Top nav row */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <button
          onClick={onBack}
          style={{
            display: "flex", alignItems: "center", gap: 5, background: "none", border: "none",
            color: COLORS.tealSoft, fontSize: 12.5, fontWeight: 700, cursor: "pointer", padding: 0,
          }}
        >
          <ChevronRight size={15} /> رجوع للمحور
        </button>
        <button
          onClick={onGoHome}
          style={{
            display: "flex", alignItems: "center", gap: 5, background: "none", border: "none",
            color: COLORS.inkSoft, fontSize: 12, fontWeight: 600, cursor: "pointer", padding: 0,
          }}
        >
          <Home size={14} /> الرئيسية
        </button>
      </div>

      {/* Lesson header */}
      <div>
        <div style={{ fontSize: 11, color: COLORS.inkSoft }}>
          المحور {module.id}: {module.title} · الدرس {lessonIndex + 1} من {module.lessons.length}
        </div>
        <div style={{ fontSize: 16, fontWeight: 800, color: COLORS.ink, marginTop: 4 }}>{lesson.title}</div>
      </div>

      {/* Reading timer */}
      <div style={{ display: "flex", alignItems: "center", gap: 10, background: "#fff", border: `1px solid ${COLORS.line}`, borderRadius: 14, padding: 12 }}>
        <div style={{ width: 36, height: 36, borderRadius: 10, flexShrink: 0, background: timeReady ? `${COLORS.teal}1A` : `${COLORS.terracotta}1A`, display: "flex", alignItems: "center", justifyContent: "center" }}>
          <Timer size={17} color={timeReady ? COLORS.teal : COLORS.terracotta} />
        </div>
        <div style={{ flex: 1 }}>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: COLORS.inkSoft, marginBottom: 4 }}>
            <span>وقت القراءة المطلوب: {minutesLabel} دقيقة تقريبًا</span>
            <span style={{ fontWeight: 700, color: timeReady ? COLORS.teal : COLORS.terracotta }}>
              {timeReady ? "اكتمل ✓" : `${timePct}%`}
            </span>
          </div>
          <ProgressBar value={timePct} color={timeReady ? COLORS.teal : COLORS.terracotta} height={5} />
        </div>
      </div>

      {/* Audio player — shown only if lesson has an audio file */}
      {lesson.audioUrl && <LessonAudioPlayer audioUrl={lesson.audioUrl} />}

      {/* Scrollable body */}
      <div
        ref={scrollRef}
        onScroll={handleScroll}
        style={{ flex: 1, background: "#fff", border: `1px solid ${COLORS.line}`, borderRadius: 16, padding: 18, maxHeight: 340, overflowY: "auto", lineHeight: 2 }}
      >
        {(lesson.body || []).filter((p) => p && p.trim()).map((para, i) => (
          <p key={i} style={{ fontSize: 13.5, color: COLORS.ink, marginTop: i === 0 ? 0 : 14, marginBottom: 0, textAlign: "right" }}>
            {para}
          </p>
        ))}
        {(!lesson.body || lesson.body.filter((p) => p && p.trim()).length === 0) && (
          <p style={{ fontSize: 13.5, color: COLORS.inkSoft, textAlign: "right", fontStyle: "italic" }}>لم يُضف محتوى لهذا الدرس بعد.</p>
        )}
        <div style={{ height: 1 }} />
        {reachedEnd && (
          <div style={{ display: "flex", alignItems: "center", gap: 6, marginTop: 14, color: COLORS.teal, fontSize: 11, fontWeight: 700 }}>
            <CheckCircle2 size={14} /> وصلت إلى نهاية الدرس
          </div>
        )}
      </div>

      {!reachedEnd && (
        <div style={{ fontSize: 11, color: COLORS.inkSoft, textAlign: "center" }}>
          استمر بالتمرير حتى نهاية النص لتفعيل تأكيد القراءة
        </div>
      )}

      {/* Confirm button */}
      <button
        onClick={() => {
          if (!canConfirm || confirmed) return;
          setConfirmed(true);
          onComplete(lesson.id);
        }}
        disabled={!canConfirm || confirmed}
        style={{
          display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
          background: confirmed ? `${COLORS.teal}1A` : canConfirm ? COLORS.teal : COLORS.sandDeep,
          color: confirmed ? COLORS.teal : canConfirm ? "#fff" : COLORS.inkSoft,
          border: confirmed ? `1.5px solid ${COLORS.teal}` : "none",
          borderRadius: 14, padding: "13px 20px", fontSize: 13, fontWeight: 800,
          cursor: canConfirm && !confirmed ? "pointer" : "not-allowed",
        }}
      >
        {confirmed ? <CheckCircle2 size={17} /> : <BookOpenCheck size={17} />}
        {confirmed
          ? "تم تسجيل قراءتك وفهمك ✓"
          : canConfirm
          ? "أكدت قراءتي وفهمي لهذا الدرس"
          : !timeReady
          ? "يرجى الانتظار حتى اكتمال وقت القراءة"
          : "استمر بالتمرير حتى نهاية الدرس"}
      </button>

      {/* Prev / Next navigation — always visible, extra prominent after confirmation */}
      <div style={{ display: "flex", gap: 8 }}>
        <button
          onClick={onPrevLesson}
          disabled={isFirst}
          style={{
            flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
            background: isFirst ? COLORS.sandDeep : "#fff",
            color: isFirst ? COLORS.inkSoft : COLORS.ink,
            border: `1px solid ${isFirst ? COLORS.line : COLORS.ink}`,
            borderRadius: 12, padding: "11px 0", fontSize: 12.5, fontWeight: 700,
            cursor: isFirst ? "not-allowed" : "pointer", opacity: isFirst ? 0.5 : 1,
          }}
        >
          <ChevronRight size={15} /> الدرس السابق
        </button>
        <button
          onClick={isLast ? onBack : onNextLesson}
          style={{
            flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
            background: confirmed ? COLORS.teal : COLORS.sandDeep,
            color: confirmed ? "#fff" : COLORS.inkSoft,
            border: "none",
            borderRadius: 12, padding: "11px 0", fontSize: 12.5, fontWeight: 800,
            cursor: "pointer",
          }}
        >
          {isLast ? (
            <><CheckCircle2 size={15} /> عودة للمحور</>
          ) : (
            <><span>الدرس التالي</span><ChevronLeft size={15} /></>
          )}
        </button>
      </div>
    </div>
  );
}

function ModuleView({ module, host, hasQuiz, onOpenLesson, onStartQuiz, onBack }) {
  const pct = moduleProgress(module, host.completedLessons);
  const Icon = module.icon || BookOpen;
  const tier = TIERS.find((t) => t.id === module.tier);
  const allDone = pct === 100;
  const canTakeQuiz = allDone && hasQuiz;

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <button
        onClick={onBack}
        style={{
          display: "flex", alignItems: "center", gap: 6, background: "none", border: "none",
          color: COLORS.tealSoft, fontSize: 13, fontWeight: 700, cursor: "pointer", padding: 0,
        }}
      >
        <ChevronRight size={16} /> رجوع للوحة التحكم
      </button>

      <div
        style={{
          background: `linear-gradient(135deg, ${tier.color}1A, ${COLORS.sand})`,
          borderRadius: 20,
          padding: 18,
          border: `1px solid ${COLORS.line}`,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 10 }}>
          <div
            style={{
              width: 48, height: 48, borderRadius: 14, background: "#fff",
              display: "flex", alignItems: "center", justifyContent: "center",
              border: `1px solid ${COLORS.line}`,
            }}
          >
            <Icon size={22} color={tier.color} />
          </div>
          <div>
            <Pill color={tier.color} bg={`${tier.color}1A`}>{tier.name}</Pill>
            <div style={{ fontSize: 17, fontWeight: 800, color: COLORS.ink, marginTop: 4 }}>
              المحور {module.id}: {module.title}
            </div>
          </div>
        </div>
        <ProgressBar value={pct} color={tier.color} />
        <div style={{ fontSize: 12, color: COLORS.inkSoft, marginTop: 6 }}>
          {pct}% مكتمل · {module.lessons.length} دروس · {module.durationMin} دقيقة إجمالاً
        </div>
      </div>

      {/* Reading requirement notice */}
      <div
        style={{
          display: "flex", alignItems: "flex-start", gap: 10, background: `${COLORS.terracotta}0D`,
          border: `1px solid ${COLORS.terracotta}33`, borderRadius: 14, padding: 12,
        }}
      >
        <BookOpenCheck size={18} color={COLORS.terracotta} style={{ flexShrink: 0, marginTop: 1 }} />
        <div style={{ fontSize: 11.5, color: COLORS.ink, lineHeight: 1.8 }}>
          قراءة كل درس بالكامل <strong>إلزامية</strong> لإتمام المحور. سيتم قياس الوقت المستغرق في القراءة، ولن يظهر زر الإتمام إلا بعد الوصول لنهاية النص وتأكيد القراءة والفهم.
        </div>
      </div>

      {/* Lessons */}
      <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
        {module.lessons.length === 0 && (
          <div style={{ fontSize: 12, color: COLORS.inkSoft, textAlign: "center", padding: 16 }}>
            لم تتم إضافة دروس لهذا المحور بعد.
          </div>
        )}
        {module.lessons.map((lesson, idx) => {
          const done = host.completedLessons.includes(lesson.id);
          return (
            <button
              key={lesson.id}
              onClick={() => onOpenLesson(lesson.id)}
              style={{
                display: "flex", alignItems: "center", gap: 12, background: "#fff",
                border: `1px solid ${COLORS.line}`, borderRadius: 14, padding: 12,
                width: "100%", textAlign: "right", cursor: "pointer",
              }}
            >
              <div
                style={{
                  width: 32, height: 32, borderRadius: "50%", flexShrink: 0,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  background: done ? tier.color : COLORS.sandDeep,
                  color: done ? "#fff" : COLORS.inkSoft,
                }}
              >
                {done ? <CheckCircle2 size={18} /> : <BookOpen size={14} />}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 13, fontWeight: 700, color: COLORS.ink }}>
                  {idx + 1}. {lesson.title}
                </div>
                <div style={{ fontSize: 11, color: COLORS.inkSoft, display: "flex", alignItems: "center", gap: 4, marginTop: 2 }}>
                  <Clock size={11} /> {lesson.durationMin} دقيقة قراءة
                </div>
              </div>
              {done ? (
                <Pill color={tier.color} bg={`${tier.color}1A`}>تمت القراءة</Pill>
              ) : (
                <ChevronLeft size={18} color={COLORS.inkSoft} />
              )}
            </button>
          );
        })}
      </div>

      {/* Quiz CTA */}
      <button
        onClick={() => onStartQuiz(module.id)}
        disabled={!canTakeQuiz}
        style={{
          display: "flex", alignItems: "center", justifyContent: "space-between", gap: 10,
          background: canTakeQuiz ? COLORS.teal : COLORS.sandDeep,
          color: canTakeQuiz ? "#fff" : COLORS.inkSoft,
          border: "none", borderRadius: 16, padding: 16,
          cursor: canTakeQuiz ? "pointer" : "not-allowed",
          width: "100%", textAlign: "right",
        }}
      >
        <div>
          <div style={{ fontSize: 13, fontWeight: 800 }}>اختبار المحور</div>
          <div style={{ fontSize: 11, opacity: 0.85, marginTop: 2 }}>
            {!allDone
              ? "أكمل قراءة جميع الدروس أولًا لفتح الاختبار"
              : !hasQuiz
              ? "لم يتم إضافة اختبار لهذا المحور بعد"
              : `${module.quizQuestions ?? "—"} أسئلة · نسبة النجاح ${module.passScore ?? 80}%`}
          </div>
        </div>
        <ClipboardCheck size={20} />
      </button>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Quiz view
// ---------------------------------------------------------------------------
function QuizView({ quiz, onFinish, onBack }) {
  const [answers, setAnswers] = useState({});
  const [submitted, setSubmitted] = useState(false);

  const score = useMemo(() => {
    if (!submitted) return null;
    const correct = quiz.questions.filter((q, i) => answers[i] === q.correct).length;
    return Math.round((correct / quiz.questions.length) * 100);
  }, [submitted, answers, quiz.questions]);

  const allAnswered = quiz.questions.every((_, i) => answers[i] !== undefined);

  if (submitted) {
    const passed = score >= quiz.passScore;
    return (
      <div style={{ display: "flex", flexDirection: "column", gap: 16, alignItems: "center", paddingTop: 24 }}>
        <div
          style={{
            width: 88, height: 88, borderRadius: "50%",
            background: passed ? `${COLORS.teal}1A` : `${COLORS.terracotta}1A`,
            display: "flex", alignItems: "center", justifyContent: "center",
          }}
        >
          {passed ? <CheckCircle2 size={44} color={COLORS.teal} /> : <AlertTriangle size={44} color={COLORS.terracotta} />}
        </div>
        <div style={{ fontSize: 20, fontWeight: 800, color: COLORS.ink }}>
          {passed ? "أحسنت! لقد نجحت" : "لم تحقق نسبة النجاح بعد"}
        </div>
        <div style={{ fontSize: 32, fontWeight: 900, color: passed ? COLORS.teal : COLORS.terracotta }}>
          {score}%
        </div>
        <div style={{ fontSize: 13, color: COLORS.inkSoft, textAlign: "center", maxWidth: 280, lineHeight: 1.8 }}>
          {passed
            ? "تم تسجيل النتيجة وإصدار إنجاز جديد في سجلك. يمكنك الانتقال للدرس التالي."
            : `نسبة النجاح المطلوبة هي ${quiz.passScore}%. راجع الدروس وأعد المحاولة — لديك محاولتان مجانيتان.`}
        </div>
        <button
          onClick={() => onFinish(score)}
          style={{
            background: COLORS.teal, color: "#fff", border: "none", borderRadius: 14,
            padding: "12px 28px", fontSize: 14, fontWeight: 700, cursor: "pointer", marginTop: 8,
          }}
        >
          {passed ? "متابعة الرحلة" : "رجوع للمحور"}
        </button>
      </div>
    );
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <button
        onClick={onBack}
        style={{
          display: "flex", alignItems: "center", gap: 6, background: "none", border: "none",
          color: COLORS.tealSoft, fontSize: 13, fontWeight: 700, cursor: "pointer", padding: 0,
        }}
      >
        <ChevronRight size={16} /> رجوع
      </button>

      <div>
        <div style={{ fontSize: 16, fontWeight: 800, color: COLORS.ink }}>{quiz.title}</div>
        <div style={{ fontSize: 12, color: COLORS.inkSoft, marginTop: 4 }}>
          {quiz.questions.length} أسئلة · نسبة النجاح {quiz.passScore}%
        </div>
      </div>

      {quiz.questions.map((q, qi) => (
        <div key={qi} style={{ background: "#fff", border: `1px solid ${COLORS.line}`, borderRadius: 16, padding: 14 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: COLORS.ink, marginBottom: 10, lineHeight: 1.7 }}>
            {qi + 1}. {q.q}
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {q.options.map((opt, oi) => {
              const selected = answers[qi] === oi;
              return (
                <button
                  key={oi}
                  onClick={() => setAnswers((a) => ({ ...a, [qi]: oi }))}
                  style={{
                    display: "flex", alignItems: "center", gap: 10, textAlign: "right",
                    border: `1.5px solid ${selected ? COLORS.teal : COLORS.line}`,
                    background: selected ? `${COLORS.teal}0D` : "#fff",
                    borderRadius: 12, padding: "10px 12px", cursor: "pointer", fontSize: 12.5,
                    color: COLORS.ink, fontWeight: selected ? 700 : 500,
                  }}
                >
                  <div
                    style={{
                      width: 18, height: 18, borderRadius: "50%", flexShrink: 0,
                      border: `2px solid ${selected ? COLORS.teal : COLORS.line}`,
                      background: selected ? COLORS.teal : "transparent",
                      display: "flex", alignItems: "center", justifyContent: "center",
                    }}
                  >
                    {selected && <div style={{ width: 7, height: 7, borderRadius: "50%", background: "#fff" }} />}
                  </div>
                  {opt}
                </button>
              );
            })}
          </div>
        </div>
      ))}

      <button
        onClick={() => setSubmitted(true)}
        disabled={!allAnswered}
        style={{
          background: allAnswered ? COLORS.teal : COLORS.sandDeep,
          color: allAnswered ? "#fff" : COLORS.inkSoft,
          border: "none", borderRadius: 14, padding: "14px 28px", fontSize: 14, fontWeight: 700,
          cursor: allAnswered ? "pointer" : "not-allowed",
        }}
      >
        إرسال الإجابات
      </button>
    </div>
  );
}

