function ProfileView({ host, onLogout, onSwitchToAdmin }) {
  const currentTier = TIERS.find((t) => t.id === host.tier);
  const [showAccountInfo, setShowAccountInfo] = useState(false);
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
  const [toast, setToast] = useState("");
  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(""), 2500); };

  const menuItems = [
    { icon: FileText, label: "بيانات الحساب", onClick: () => setShowAccountInfo((s) => !s) },
    { icon: LogOut, label: "تسجيل الخروج", onClick: () => setShowLogoutConfirm(true), danger: true },
  ];

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16, position: "relative" }}>

      {/* Toast */}
      {toast && (
        <div style={{
          position: "fixed", bottom: 90, left: "50%", transform: "translateX(-50%)",
          background: COLORS.ink, color: "#fff", borderRadius: 14, padding: "10px 18px",
          fontSize: 12.5, fontWeight: 600, zIndex: 999, whiteSpace: "nowrap",
          boxShadow: "0 4px 20px rgba(0,0,0,0.25)",
        }}>{toast}</div>
      )}

      {/* Logout confirmation dialog */}
      {showLogoutConfirm && (
        <div style={{
          position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)",
          display: "flex", alignItems: "center", justifyContent: "center",
          zIndex: 1000, padding: 24,
        }}
          onClick={() => setShowLogoutConfirm(false)}
        >
          <div
            dir="rtl"
            style={{
              background: "#fff", borderRadius: 20, padding: 24,
              width: "100%", maxWidth: 320,
              boxShadow: "0 20px 60px rgba(0,0,0,0.3)",
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <div style={{ display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 16 }}>
              <div style={{
                width: 52, height: 52, borderRadius: 16,
                background: "#FEE2E2", display: "flex", alignItems: "center", justifyContent: "center",
              }}>
                <LogOut size={22} color="#C0392B" />
              </div>
            </div>
            <div style={{ fontSize: 16, fontWeight: 800, color: COLORS.ink, textAlign: "center", marginBottom: 8 }}>
              تسجيل الخروج
            </div>
            <div style={{ fontSize: 13, color: COLORS.inkSoft, textAlign: "center", marginBottom: 24, lineHeight: 1.7 }}>
              هل تريد تسجيل الخروج من حسابك؟<br/>يمكنك الدخول مجدداً في أي وقت.
            </div>
            <div style={{ display: "flex", gap: 10 }}>
              <button
                onClick={() => setShowLogoutConfirm(false)}
                style={{
                  flex: 1, padding: "12px 0", borderRadius: 12, border: `1px solid ${COLORS.line}`,
                  background: "#fff", color: COLORS.ink, fontSize: 13, fontWeight: 700, cursor: "pointer",
                }}
              >
                إلغاء
              </button>
              <button
                onClick={() => { setShowLogoutConfirm(false); onLogout(); }}
                style={{
                  flex: 1, padding: "12px 0", borderRadius: 12, border: "none",
                  background: "#C0392B", color: "#fff", fontSize: 13, fontWeight: 700, cursor: "pointer",
                }}
              >
                تسجيل الخروج
              </button>
            </div>
          </div>
        </div>
      )}
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 10, padding: "12px 0" }}>
        <div
          style={{
            width: 80, height: 80, borderRadius: "50%", background: COLORS.teal,
            display: "flex", alignItems: "center", justifyContent: "center", fontSize: 28,
            fontWeight: 800, color: "#fff",
          }}
        >
          {host.name.charAt(0)}
        </div>
        <div style={{ fontSize: 16, fontWeight: 800, color: COLORS.ink }}>{host.name}</div>
        <div style={{ fontSize: 12, color: COLORS.inkSoft }}>
          {host.district ? `${host.district}، ` : ""}{host.city} · منذ {host.joinedAt}
        </div>
        <Pill color={currentTier.color} bg={`${currentTier.color}1A`}>{currentTier.name}</Pill>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
        {[
          { label: "النقاط", value: host.points, icon: TrendingUp },
          { label: "الشهادات", value: host.certificates.length, icon: Award },
          { label: "الدروس المكتملة", value: host.completedLessons.length, icon: BookOpen },
          { label: "التقييم", value: host.rating ? host.rating.toFixed(1) : "—", icon: Star },
        ].map((stat) => (
          <div key={stat.label} style={{ background: "#fff", border: `1px solid ${COLORS.line}`, borderRadius: 14, padding: 14 }}>
            <stat.icon size={18} color={COLORS.teal} />
            <div style={{ fontSize: 20, fontWeight: 800, color: COLORS.ink, marginTop: 8 }}>{stat.value}</div>
            <div style={{ fontSize: 11, color: COLORS.inkSoft, marginTop: 2 }}>{stat.label}</div>
          </div>
        ))}
      </div>

      {showAccountInfo && (
        <div style={{ background: "#fff", border: `1px solid ${COLORS.line}`, borderRadius: 14, padding: 14, display: "flex", flexDirection: "column", gap: 10 }}>
          <div style={{ fontSize: 12.5, fontWeight: 800, color: COLORS.ink }}>بيانات الحساب</div>
          {[
            { label: "البريد الإلكتروني", value: host.email },
            { label: "رقم الهاتف", value: host.phone || "—" },
            { label: "الحي / المنطقة", value: host.district || "—" },
          ].map((row) => (
            <div key={row.label} style={{ display: "flex", justifyContent: "space-between", fontSize: 12.5 }}>
              <span style={{ color: COLORS.inkSoft }}>{row.label}</span>
              <span style={{ color: COLORS.ink, fontWeight: 600 }}>{row.value}</span>
            </div>
          ))}
        </div>
      )}

      {/* Admin panel access — prominent card */}
      <button
        onClick={onSwitchToAdmin}
        style={{
          width: "100%", display: "flex", alignItems: "center", gap: 14,
          background: `linear-gradient(135deg, #1B4D4A, #2E6E69)`,
          border: "none", borderRadius: 16, padding: "16px 18px",
          cursor: "pointer", textAlign: "right",
          boxShadow: "0 4px 20px rgba(27,77,74,0.25)",
        }}
      >
        <div style={{
          width: 44, height: 44, borderRadius: 14, flexShrink: 0,
          background: "rgba(255,255,255,0.15)",
          display: "flex", alignItems: "center", justifyContent: "center",
        }}>
          <Database size={20} color="#F5E6C8" />
        </div>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 14, fontWeight: 800, color: "#fff" }}>لوحة المشرف</div>
          <div style={{ fontSize: 11, color: "rgba(255,255,255,0.65)", marginTop: 3 }}>
            إدارة المحاور · الاختبارات · المستضيفون
          </div>
        </div>
        <ChevronLeft size={18} color="rgba(255,255,255,0.5)" />
      </button>

      <div style={{ background: "#fff", border: `1px solid ${COLORS.line}`, borderRadius: 14, overflow: "hidden" }}>
        {menuItems.map((item, i) => (
          <div
            key={item.label}
            onClick={item.onClick || undefined}
            style={{
              display: "flex", alignItems: "center", gap: 12, padding: "13px 14px",
              borderBottom: i < menuItems.length - 1 ? `1px solid ${COLORS.line}` : "none",
              cursor: item.onClick ? "pointer" : "default",
            }}
          >
            <item.icon size={17} color={item.danger ? "#C0392B" : COLORS.inkSoft} />
            <span style={{ fontSize: 13, color: item.danger ? "#C0392B" : COLORS.ink, fontWeight: 600, flex: 1 }}>{item.label}</span>
            {item.label === "بيانات الحساب" ? (
              showAccountInfo ? <ChevronUp size={16} color={COLORS.inkSoft} /> : <ChevronDown size={16} color={COLORS.inkSoft} />
            ) : (
              <ChevronLeft size={16} color={COLORS.inkSoft} />
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Host authentication screen — login / signup
// ---------------------------------------------------------------------------
const MEDINA_DISTRICTS = [
  "العوالي", "قباء", "الحرة الشرقية", "الحرة الغربية", "العزيزية",
  "أبيار علي", "الدفاع", "الخالدية", "النبلاء", "الرانوناء",
  "البيوت", "الفتح", "السلام", "السيح", "الشهداء",
  "طيبة", "الجامعة", "المهاجرين", "الأنصار", "بني خدرة",
  "حي آخر",
];

function HostAuthScreen({ onSignup, onLogin, busy, error, clearError, onSwitchToAdmin }) {
  const [mode, setMode] = useState("login");
  const [form, setForm] = useState({ name: "", email: "", phone: "", district: "", password: "" });
  const [loginForm, setLoginForm] = useState({ email: "", password: "" });

  const loginRef = useRef({ email: "", password: "" });
  const formRef = useRef({ name: "", email: "", phone: "", district: "", password: "" });

  const update = (field, value) => {
    clearError();
    formRef.current = { ...formRef.current, [field]: value };
    setForm((f) => ({ ...f, [field]: value }));
  };
  const updateLogin = (field, value) => {
    clearError();
    loginRef.current = { ...loginRef.current, [field]: value };
    setLoginForm((f) => ({ ...f, [field]: value }));
  };

  const handleLogin = () => onLogin(loginRef.current);

  const handleKeyDown = (e, action) => {
    if (e.key === "Enter") { e.preventDefault(); action(); }
  };

  return (
    <div
      dir="rtl"
      style={{
        fontFamily: "'Tahoma', 'Segoe UI', system-ui, sans-serif",
        background: COLORS.sand,
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 18,
      }}
    >
      <div style={{ width: "100%", maxWidth: 380 }}>
        <ACard style={{ display: "flex", flexDirection: "column", gap: 14 }}>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 8, marginBottom: 4 }}>
            {/* Real logo */}
            <div style={{
              width: 140, height: 60,
              display: "flex", alignItems: "center", justifyContent: "center",
            }}>
              <img
                src={LOGO_URL}
                alt="Medina Homestays"
                style={{ width: "100%", height: "100%", objectFit: "contain" }}
              />
            </div>
            <div style={{ fontSize: 14, fontWeight: 800, color: COLORS.ink }}>أكاديمية المستضيف</div>
            <div style={{ fontSize: 11, color: COLORS.inkSoft, textAlign: "center" }}>
              برنامج اعتماد المستضيفين الرسمي
            </div>
          </div>

          {/* Mode toggle */}
          <div style={{ display: "flex", gap: 6, background: COLORS.sandDeep, borderRadius: 12, padding: 4 }}>
            <button
              onClick={() => { setMode("login"); clearError(); }}
              style={{
                flex: 1, border: "none", borderRadius: 10, padding: "9px 0",
                background: mode === "login" ? "#fff" : "transparent",
                color: mode === "login" ? COLORS.teal : COLORS.inkSoft,
                fontSize: 12.5, fontWeight: 700, cursor: "pointer",
                boxShadow: mode === "login" ? "0 1px 4px rgba(0,0,0,0.08)" : "none",
              }}
            >
              تسجيل الدخول
            </button>
            <button
              onClick={() => { setMode("signup"); clearError(); }}
              style={{
                flex: 1, border: "none", borderRadius: 10, padding: "9px 0",
                background: mode === "signup" ? "#fff" : "transparent",
                color: mode === "signup" ? COLORS.teal : COLORS.inkSoft,
                fontSize: 12.5, fontWeight: 700, cursor: "pointer",
                boxShadow: mode === "signup" ? "0 1px 4px rgba(0,0,0,0.08)" : "none",
              }}
            >
              مستضيف جديد
            </button>
          </div>

          {mode === "login" ? (
            <>
              <AField label="البريد الإلكتروني">
                <AInput
                  type="email"
                  value={loginForm.email}
                  onChange={(e) => updateLogin("email", e.target.value)}
                  onKeyDown={(e) => handleKeyDown(e, handleLogin)}
                  autoFocus
                  placeholder="example@email.com"
                />
              </AField>
              <AField label="كلمة المرور">
                <AInput
                  type="password"
                  value={loginForm.password}
                  onChange={(e) => updateLogin("password", e.target.value)}
                  onKeyDown={(e) => handleKeyDown(e, handleLogin)}
                  placeholder="أدخل كلمة المرور"
                />
              </AField>

              {error && (
                <div style={{ fontSize: 12, color: "#C0392B", background: "#C0392B0D", borderRadius: 10, padding: "10px 12px", lineHeight: 1.7 }}>
                  <div style={{ fontWeight: 700, marginBottom: 4 }}>{error}</div>
                  {(error.includes("بريد") || error.includes("مرور")) && (
                    <div style={{ opacity: 0.85 }}>
                      ملاحظة: إذا كنت سجّلت بجهاز آخر أو متصفح مختلف، فالحسابات غير مشتركة حاليًا — أنشئ حسابًا جديدًا بنفس البريد على هذا الجهاز.
                    </div>
                  )}
                </div>
              )}

              <AButton onClick={handleLogin} disabled={busy}>
                {busy ? "جارٍ تسجيل الدخول..." : "دخول →"}
              </AButton>
            </>
          ) : (
            <>
              <AField label="الاسم الكامل">
                <AInput
                  value={form.name}
                  onChange={(e) => update("name", e.target.value)}
                  autoFocus
                />
              </AField>
              <AField label="البريد الإلكتروني">
                <AInput
                  type="email"
                  value={form.email}
                  onChange={(e) => update("email", e.target.value)}
                />
              </AField>
              <AField label="رقم الهاتف">
                <AInput
                  type="tel"
                  value={form.phone}
                  onChange={(e) => update("phone", e.target.value)}
                  placeholder="05xxxxxxxx"
                  dir="ltr"
                  style={{ textAlign: "right" }}
                />
              </AField>
              <AField label="الحي / المنطقة في المدينة المنورة">
                <select
                  dir="rtl"
                  style={inputStyle}
                  value={form.district}
                  onChange={(e) => update("district", e.target.value)}
                >
                  <option value="">اختر الحي...</option>
                  {MEDINA_DISTRICTS.map((d) => <option key={d} value={d}>{d}</option>)}
                </select>
              </AField>
              <AField label="كلمة المرور">
                <AInput
                  type="password"
                  value={form.password}
                  onChange={(e) => update("password", e.target.value)}
                  onKeyDown={(e) => handleKeyDown(e, () => onSignup(formRef.current))}
                  placeholder="6 أحرف على الأقل"
                />
              </AField>

              {error && (
                <div style={{ fontSize: 12, color: "#C0392B", background: "#C0392B0D", borderRadius: 10, padding: "8px 12px" }}>
                  {error}
                </div>
              )}

              <AButton onClick={() => onSignup(formRef.current)} disabled={busy}>
                {busy ? "جارٍ إنشاء الحساب..." : "إنشاء حساب وبدء التدريب"}
              </AButton>
              <div style={{ fontSize: 10.5, color: COLORS.inkSoft, textAlign: "center", lineHeight: 1.8 }}>
                بإنشاء الحساب، فإنك توافق على ميثاق أخلاقيات المستضيف المعروض في المحور الأول من برنامج الاعتماد.
              </div>
            </>
          )}
        </ACard>

        {/* Admin access button */}
        <button
          onClick={onSwitchToAdmin}
          style={{
            marginTop: 14, width: "100%",
            display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
            background: "rgba(27,77,74,0.07)", border: "1px solid rgba(27,77,74,0.2)",
            borderRadius: 14, padding: "12px 0",
            cursor: "pointer", color: COLORS.teal, fontSize: 13, fontWeight: 700,
            fontFamily: "inherit",
          }}
        >
          <ShieldCheck size={15} color={COLORS.teal} />
          دخول لوحة المشرف
        </button>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Root app
// ---------------------------------------------------------------------------
const NAV_ITEMS = [
  { id: "home", label: "الرئيسية", icon: Home },
  { id: "modules", label: "البرنامج", icon: BookOpen },
  { id: "certificates", label: "شهاداتي", icon: Award },
  { id: "profile", label: "حسابي", icon: User },
];

function HostApp({ hostId, onSwitchToAdmin, onLogout }) {
  const { host, loaded: hostLoaded, completeLesson, recordQuiz } = useHostData(hostId);
  const { modules, quizzes, loaded: contentLoaded } = useContentData();
  const loaded = hostLoaded && contentLoaded;
  const [tab, setTab] = useState("home");
  const [activeTierId, setActiveTierId] = useState("basic");
  const [openModuleId, setOpenModuleId] = useState(null);
  const [openLessonId, setOpenLessonId] = useState(null);
  const [quizModuleId, setQuizModuleId] = useState(null);

  const openModule = modules.find((m) => m.id === openModuleId);
  const openLesson = openModule?.lessons.find((l) => l.id === openLessonId);
  const openLessonIndex = openModule?.lessons.findIndex((l) => l.id === openLessonId);
  const activeQuiz = quizModuleId ? quizzes[quizModuleId] : null;

  const handleQuizFinish = (score) => {
    recordQuiz(quizModuleId, score, activeQuiz?.passScore ?? 80);
    setQuizModuleId(null);
  };

  let content;
  if (quizModuleId && activeQuiz) {
    content = (
      <QuizView quiz={activeQuiz} onFinish={handleQuizFinish} onBack={() => setQuizModuleId(null)} />
    );
  } else if (openModule && openLesson) {
    const lessons = openModule.lessons;
    const prevLesson = openLessonIndex > 0 ? lessons[openLessonIndex - 1] : null;
    const nextLesson = openLessonIndex < lessons.length - 1 ? lessons[openLessonIndex + 1] : null;
    content = (
      <LessonReader
        module={openModule}
        lesson={openLesson}
        lessonIndex={openLessonIndex}
        onComplete={completeLesson}
        onBack={() => setOpenLessonId(null)}
        onPrevLesson={() => prevLesson && setOpenLessonId(prevLesson.id)}
        onNextLesson={() => nextLesson && setOpenLessonId(nextLesson.id)}
        onGoHome={() => { setOpenModuleId(null); setOpenLessonId(null); setTab("home"); }}
      />
    );
  } else if (openModule) {
    content = (
      <ModuleView
        module={openModule}
        host={host}
        hasQuiz={!!quizzes[openModule.id]}
        onOpenLesson={(id) => setOpenLessonId(id)}
        onStartQuiz={(id) => setQuizModuleId(id)}
        onBack={() => setOpenModuleId(null)}
      />
    );
  } else if (tab === "home") {
    content = (
      <Dashboard
        host={host}
        modules={modules}
        onOpenModule={(id) => setOpenModuleId(id)}
        onSelectTier={setActiveTierId}
        activeTierId={activeTierId}
      />
    );
  } else if (tab === "modules") {
    content = (
      <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
        <div>
          <div style={{ fontSize: 16, fontWeight: 800, color: COLORS.ink }}>برنامج الاعتماد الكامل</div>
          <div style={{ fontSize: 12, color: COLORS.inkSoft, marginTop: 4 }}>
            {modules.length} محاور موزعة على 4 مستويات اعتماد
          </div>
        </div>
        {TIERS.map((tier) => {
          const tierMods = modules.filter((m) => m.tier === tier.id);
          const TIcon = tier.icon;
          return (
            <div key={tier.id}>
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8, paddingInline: 4 }}>
                <TIcon size={16} color={tier.color} />
                <span style={{ fontSize: 13, fontWeight: 800, color: COLORS.ink }}>{tier.name}</span>
                <span style={{ fontSize: 11, color: COLORS.inkSoft }}>· {tier.hours} ساعة</span>
              </div>
              {tierMods.length === 0 ? (
                <div style={{ fontSize: 12, color: COLORS.inkSoft, padding: "8px 4px" }}>
                  يعتمد على الخبرة الفعلية والتقييم الميداني
                </div>
              ) : (
                <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                  {tierMods.map((mod) => {
                    const pct = moduleProgress(mod, host.completedLessons);
                    const Icon = mod.icon || BookOpen;
                    return (
                      <button
                        key={mod.id}
                        onClick={() => setOpenModuleId(mod.id)}
                        style={{
                          display: "flex", alignItems: "center", gap: 12, background: "#fff",
                          border: `1px solid ${COLORS.line}`, borderRadius: 14, padding: 12,
                          textAlign: "right", cursor: "pointer", width: "100%",
                        }}
                      >
                        <div
                          style={{
                            width: 38, height: 38, borderRadius: 10,
                            background: pct === 100 ? `${tier.color}1A` : COLORS.sandDeep,
                            display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0,
                          }}
                        >
                          {pct === 100 ? <CheckCircle2 size={17} color={tier.color} /> : <Icon size={17} color={COLORS.inkSoft} />}
                        </div>
                        <div style={{ flex: 1 }}>
                          <div style={{ fontSize: 12.5, fontWeight: 700, color: COLORS.ink }}>{mod.id}. {mod.title}</div>
                          <div style={{ fontSize: 10.5, color: COLORS.inkSoft, marginTop: 2 }}>{pct}% مكتمل</div>
                        </div>
                        <ChevronLeft size={16} color={COLORS.inkSoft} />
                      </button>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>
    );
  } else if (tab === "certificates") {
    content = <CertificatesView host={host} modules={modules} />;
  } else if (tab === "profile") {
    content = <ProfileView host={host} onLogout={onLogout} onSwitchToAdmin={onSwitchToAdmin} />;
  }

  return (
    <div
      dir="rtl"
      style={{
        fontFamily: "'Tahoma', 'Segoe UI', system-ui, sans-serif",
        background: COLORS.sand,
        minHeight: "100vh",
        display: "flex",
        justifyContent: "center",
      }}
    >
      <div style={{ width: "100%", maxWidth: 430, minHeight: "100vh", display: "flex", flexDirection: "column" }}>
        {/* Top bar */}
        <div
          style={{
            display: "flex", alignItems: "center", justifyContent: "space-between",
            padding: "16px 18px 10px", position: "sticky", top: 0, background: COLORS.sand, zIndex: 10,
          }}
        >
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <img
              src={LOGO_URL}
              alt="Medina Homestays"
              style={{ height: 36, width: "auto", objectFit: "contain" }}
            />
          </div>
        </div>

        {/* Content */}
        <div style={{ flex: 1, padding: "8px 18px 90px" }}>
          {!loaded ? (
            <div style={{ textAlign: "center", padding: 60, color: COLORS.inkSoft, fontSize: 13 }}>
              جاري تحميل بياناتك...
            </div>
          ) : (
            content
          )}
        </div>

        {/* Bottom nav */}
        <div
          style={{
            position: "fixed", bottom: 0, left: "50%", transform: "translateX(-50%)",
            width: "100%", maxWidth: 430, background: "#fff", borderTop: `1px solid ${COLORS.line}`,
            display: "flex", justifyContent: "space-around", padding: "10px 8px",
            boxShadow: "0 -4px 16px rgba(0,0,0,0.04)",
          }}
        >
          {NAV_ITEMS.map((item) => {
            const active = tab === item.id && !openModule && !quizModuleId;
            return (
              <button
                key={item.id}
                onClick={() => {
                  setTab(item.id);
                  setOpenModuleId(null);
                  setOpenLessonId(null);
                  setQuizModuleId(null);
                }}
                style={{
                  display: "flex", flexDirection: "column", alignItems: "center", gap: 4,
                  background: "none", border: "none", cursor: "pointer",
                  color: active ? COLORS.teal : COLORS.inkSoft, padding: "4px 10px",
                }}
              >
                <item.icon size={20} strokeWidth={active ? 2.4 : 2} />
                <span style={{ fontSize: 10, fontWeight: active ? 700 : 500 }}>{item.label}</span>
              </button>
            );
          })}

          {/* Admin button — prominent, clearly labeled */}
          <button
            onClick={onSwitchToAdmin}
            style={{
              display: "flex", flexDirection: "column", alignItems: "center", gap: 3,
              background: "none", border: "none", cursor: "pointer",
              color: COLORS.terracotta, padding: "2px 6px",
            }}
          >
            <div style={{
              width: 32, height: 24, borderRadius: 8,
              background: `${COLORS.terracotta}22`,
              border: `1.5px solid ${COLORS.terracotta}44`,
              display: "flex", alignItems: "center", justifyContent: "center",
              gap: 3,
            }}>
              <ShieldCheck size={13} color={COLORS.terracotta} strokeWidth={2.2} />
            </div>
            <span style={{ fontSize: 9, fontWeight: 700, color: COLORS.terracotta, whiteSpace: "nowrap" }}>المشرف</span>
          </button>
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Admin UI primitives
// ---------------------------------------------------------------------------
function AField({ label, children }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
      <label style={{ fontSize: 11.5, fontWeight: 700, color: COLORS.inkSoft }}>{label}</label>
      {children}
    </div>
  );
}

const inputStyle = {
  border: `1px solid ${COLORS.line}`,
  borderRadius: 10,
  padding: "10px 12px",
  fontSize: 13,
  color: COLORS.ink,
  background: "#fff",
  fontFamily: "inherit",
  width: "100%",
  boxSizing: "border-box",
};

function AInput(props) {
  return <input dir="rtl" style={inputStyle} {...props} />;
}

function ATextarea(props) {
  return <textarea dir="rtl" style={{ ...inputStyle, resize: "vertical", lineHeight: 1.7 }} {...props} />;
}

function AButton({ children, variant = "primary", ...rest }) {
  const variants = {
    primary: { background: COLORS.teal, color: "#fff", border: "none" },
    secondary: { background: "#fff", color: COLORS.ink, border: `1px solid ${COLORS.line}` },
    danger: { background: "#fff", color: "#C0392B", border: `1px solid #C0392B33` },
    ghost: { background: "transparent", color: COLORS.tealSoft, border: "none" },
  };
  return (
    <button
      {...rest}
      style={{
        display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
        borderRadius: 10, padding: "9px 14px", fontSize: 12.5, fontWeight: 700,
        cursor: "pointer", ...variants[variant], ...(rest.style || {}),
      }}
    >
      {children}
    </button>
  );
}

function ACard({ children, style }) {
  return (
    <div style={{ background: "#fff", border: `1px solid ${COLORS.line}`, borderRadius: 14, padding: 14, ...style }}>
      {children}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Admin: Modules & Lessons editor
// ---------------------------------------------------------------------------
const TIER_OPTIONS = TIERS.map((t) => ({ value: t.id, label: t.name }));

// ---------------------------------------------------------------------------
// Admin: Audio upload + record for a lesson
// Supports: (1) upload audio file  (2) record from microphone
// The audio is stored as a base64 data URL in lesson.audioUrl
// For production: replace with Firebase Storage upload → store the download URL
// ---------------------------------------------------------------------------
function AdminLessonAudio({ audioUrl, onChange }) {
  const [mode, setMode] = useState("idle"); // "idle" | "recording" | "preview"
  const [recording, setRecording] = useState(false);
  const [recSeconds, setRecSeconds] = useState(0);
  const mediaRef = useRef(null);
  const chunksRef = useRef([]);
  const timerRef = useRef(null);
  const fileRef = useRef(null);
  const previewRef = useRef(null);

  const hasAudio = !!audioUrl;

  // ── File upload ──────────────────────────────────────────────────────────
  const handleFileChange = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 20 * 1024 * 1024) {
      alert("الحجم الأقصى للملف الصوتي هو 20 ميغابايت.");
      return;
    }
    const reader = new FileReader();
    reader.onload = (ev) => onChange(ev.target.result);
    reader.readAsDataURL(file);
  };

  // ── Microphone recording ─────────────────────────────────────────────────
  const startRecord = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mr = new MediaRecorder(stream);
      mediaRef.current = mr;
      chunksRef.current = [];
      mr.ondataavailable = (e) => { if (e.data.size > 0) chunksRef.current.push(e.data); };
      mr.onstop = () => {
        stream.getTracks().forEach((t) => t.stop());
        const blob = new Blob(chunksRef.current, { type: "audio/webm" });
        const reader = new FileReader();
        reader.onload = (ev) => onChange(ev.target.result);
        reader.readAsDataURL(blob);
        clearInterval(timerRef.current);
      };
      mr.start();
      setRecording(true);
      setRecSeconds(0);
      setMode("recording");
      timerRef.current = setInterval(() => setRecSeconds((s) => s + 1), 1000);
    } catch (err) {
      alert("تعذّر الوصول للميكروفون. يرجى السماح بالإذن من إعدادات المتصفح.");
    }
  };

  const stopRecord = () => {
    if (mediaRef.current && mediaRef.current.state !== "inactive") {
      mediaRef.current.stop();
    }
    setRecording(false);
    setMode("idle");
  };

  const fmt = (s) => `${Math.floor(s / 60)}:${String(s % 60).padStart(2, "0")}`;

  return (
    <div style={{
      background: `${COLORS.teal}08`,
      border: `1px solid ${COLORS.teal}25`,
      borderRadius: 12, padding: 12,
      display: "flex", flexDirection: "column", gap: 10,
    }}>
      <div style={{ fontSize: 11, fontWeight: 800, color: COLORS.teal, display: "flex", alignItems: "center", gap: 6 }}>
        🎙️ الصوت التوضيحي للدرس
        <span style={{ fontSize: 10, fontWeight: 400, color: COLORS.inkSoft }}>— اختياري</span>
      </div>

      {/* Current audio preview */}
      {hasAudio && (
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <audio ref={previewRef} src={audioUrl} controls style={{ flex: 1, height: 32, borderRadius: 8 }} />
          <button
            onClick={() => onChange("")}
            style={{ background: "#C0392B15", border: "1px solid #C0392B30", borderRadius: 8, padding: "5px 10px", color: "#C0392B", fontSize: 11, fontWeight: 700, cursor: "pointer" }}
          >
            <Trash2 size={12} /> حذف
          </button>
        </div>
      )}

      {/* Controls */}
      {mode !== "recording" && (
        <div style={{ display: "flex", gap: 8 }}>
          {/* Upload file */}
          <button
            onClick={() => fileRef.current?.click()}
            style={{
              flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
              background: "#fff", border: `1px solid ${COLORS.line}`,
              borderRadius: 10, padding: "9px 0", fontSize: 11.5, fontWeight: 700,
              color: COLORS.ink, cursor: "pointer",
            }}
          >
            <Upload size={13} /> رفع ملف صوتي
          </button>
          <input ref={fileRef} type="file" accept="audio/*" style={{ display: "none" }} onChange={handleFileChange} />

          {/* Record */}
          <button
            onClick={startRecord}
            style={{
              flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
              background: COLORS.teal, border: "none",
              borderRadius: 10, padding: "9px 0", fontSize: 11.5, fontWeight: 700,
              color: "#fff", cursor: "pointer",
            }}
          >
            🎙️ تسجيل صوتي
          </button>
        </div>
      )}

      {/* Recording in progress */}
      {mode === "recording" && (
        <div style={{ display: "flex", alignItems: "center", gap: 10, background: "#C0392B10", border: "1px solid #C0392B30", borderRadius: 10, padding: "10px 14px" }}>
          <div style={{ width: 10, height: 10, borderRadius: "50%", background: "#C0392B", animation: "pulse 1s ease-in-out infinite" }} />
          <span style={{ fontSize: 12, fontWeight: 700, color: "#C0392B", flex: 1 }}>جارٍ التسجيل... {fmt(recSeconds)}</span>
          <button
            onClick={stopRecord}
            style={{ background: "#C0392B", border: "none", borderRadius: 8, padding: "7px 14px", color: "#fff", fontSize: 12, fontWeight: 700, cursor: "pointer" }}
          >
            إيقاف ✓
          </button>
        </div>
      )}

      {!hasAudio && mode !== "recording" && (
        <div style={{ fontSize: 10, color: COLORS.inkSoft, textAlign: "center" }}>
          MP3 · WAV · M4A · الحجم الأقصى 20 MB
        </div>
      )}
    </div>
  );
}

function AdminModulesSection({ modules, saveModule, deleteModule }) {
  const [expandedId, setExpandedId] = useState(null);
  const [draft, setDraft] = useState(null); // working copy of module being edited
  const [savingId, setSavingId] = useState(null);

  const startEdit = (mod) => {
    setExpandedId(mod.id);
    setDraft(JSON.parse(JSON.stringify({ ...mod, icon: undefined })));
  };

  const addModule = () => {
    if (draft && !modules.some((m) => m.id === draft.id)) {
      if (!window.confirm("لديك محور جديد غير محفوظ. سيتم تجاهله إذا أنشأت محورًا آخر. هل تريد الاستمرار؟")) return;
    }
    const nextId = modules.length ? Math.max(...modules.map((m) => m.id)) + 1 : 1;
    const newMod = {
      id: nextId, tier: "basic", title: "محور جديد", titleEn: "New Module",
      durationMin: 30, quizQuestions: 10, passScore: 80, lessons: [],
    };
    setExpandedId(nextId);
    setDraft(newMod);
  };

  const updateField = (field, value) => setDraft((d) => ({ ...d, [field]: value }));

  const updateLesson = (idx, field, value) => {
    setDraft((d) => {
      const lessons = [...d.lessons];
      lessons[idx] = { ...lessons[idx], [field]: value };
      return { ...d, lessons };
    });
  };

  const updateLessonParagraph = (lessonIdx, paraIdx, value) => {
    setDraft((d) => {
      const lessons = [...d.lessons];
      const body = [...(lessons[lessonIdx].body || [])];
      body[paraIdx] = value;
      lessons[lessonIdx] = { ...lessons[lessonIdx], body };
      return { ...d, lessons };
    });
  };

  const addParagraph = (lessonIdx) => {
    setDraft((d) => {
      const lessons = [...d.lessons];
      const body = [...(lessons[lessonIdx].body || []), ""];
      lessons[lessonIdx] = { ...lessons[lessonIdx], body };
      return { ...d, lessons };
    });
  };

  const removeParagraph = (lessonIdx, paraIdx) => {
    setDraft((d) => {
      const lessons = [...d.lessons];
      const body = (lessons[lessonIdx].body || []).filter((_, i) => i !== paraIdx);
      lessons[lessonIdx] = { ...lessons[lessonIdx], body };
      return { ...d, lessons };
    });
  };

  const addLesson = () => {
    setDraft((d) => {
      const existingNums = d.lessons
        .map((l) => {
          const parts = String(l.id).split("-");
          const n = Number(parts[parts.length - 1]);
          return Number.isFinite(n) ? n : 0;
        });
      const nextNum = (existingNums.length ? Math.max(...existingNums) : 0) + 1;
      const newLesson = { id: `${d.id}-${nextNum}`, title: "درس جديد", durationMin: 10, body: [""] };
      return { ...d, lessons: [...d.lessons, newLesson] };
    });
  };

  const removeLesson = (idx) => {
    setDraft((d) => ({ ...d, lessons: d.lessons.filter((_, i) => i !== idx) }));
  };

  const moveLesson = (idx, dir) => {
    setDraft((d) => {
      const lessons = [...d.lessons];
      const newIdx = idx + dir;
      if (newIdx < 0 || newIdx >= lessons.length) return d;
      [lessons[idx], lessons[newIdx]] = [lessons[newIdx], lessons[idx]];
      return { ...d, lessons };
    });
  };

  const handleSave = async () => {
    setSavingId(draft.id);
    await saveModule(draft);
    setSavingId(null);
    setExpandedId(null);
    setDraft(null);
  };

  const handleCancel = () => {
    setExpandedId(null);
    setDraft(null);
  };

  const handleDelete = async (mod) => {
    if (!window.confirm(`هل تريد حذف المحور "${mod.title}"؟ لا يمكن التراجع عن هذا الإجراء.`)) return;
    await deleteModule(mod.id);
    if (expandedId === mod.id) { setExpandedId(null); setDraft(null); }
  };

  const isNewModule = draft && !modules.some((m) => m.id === draft.id);

  const renderEditorForm = () => (
    <div style={{ marginTop: 14, paddingTop: 14, borderTop: `1px solid ${COLORS.line}`, display: "flex", flexDirection: "column", gap: 12 }}>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
        <AField label="عنوان المحور (عربي)">
          <AInput value={draft.title} onChange={(e) => updateField("title", e.target.value)} />
        </AField>
        <AField label="العنوان بالإنجليزية">
          <AInput value={draft.titleEn || ""} onChange={(e) => updateField("titleEn", e.target.value)} />
        </AField>
        <AField label="المستوى">
          <select dir="rtl" style={inputStyle} value={draft.tier} onChange={(e) => updateField("tier", e.target.value)}>
            {TIER_OPTIONS.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
          </select>
        </AField>
        <AField label="المدة الإجمالية (دقيقة)">
          <AInput type="number" value={draft.durationMin} onChange={(e) => updateField("durationMin", Number(e.target.value))} />
        </AField>
        <AField label="عدد أسئلة الاختبار">
          <AInput type="number" value={draft.quizQuestions || 0} onChange={(e) => updateField("quizQuestions", Number(e.target.value))} />
        </AField>
        <AField label="نسبة النجاح (%)">
          <AInput type="number" value={draft.passScore || 80} onChange={(e) => updateField("passScore", Number(e.target.value))} />
        </AField>
      </div>

      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 4 }}>
        <div style={{ fontSize: 12.5, fontWeight: 800, color: COLORS.ink }}>الدروس ({draft.lessons.length})</div>
        <AButton variant="secondary" onClick={addLesson}><Plus size={13} /> درس جديد</AButton>
      </div>

      {draft.lessons.length === 0 && (
        <div style={{ fontSize: 11.5, color: COLORS.inkSoft, textAlign: "center", padding: "8px 0" }}>
          لا توجد دروس بعد. أضف درسًا للبدء.
        </div>
      )}

      {draft.lessons.map((lesson, lidx) => (
        <div key={lesson.id} style={{ border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 10, background: COLORS.sand }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
            <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
              <button onClick={() => moveLesson(lidx, -1)} disabled={lidx === 0} style={{ background: "none", border: "none", cursor: lidx === 0 ? "default" : "pointer", padding: 0, opacity: lidx === 0 ? 0.3 : 1 }}>
                <ChevronUp size={14} color={COLORS.inkSoft} />
              </button>
              <button onClick={() => moveLesson(lidx, 1)} disabled={lidx === draft.lessons.length - 1} style={{ background: "none", border: "none", cursor: lidx === draft.lessons.length - 1 ? "default" : "pointer", padding: 0, opacity: lidx === draft.lessons.length - 1 ? 0.3 : 1 }}>
                <ChevronDown size={14} color={COLORS.inkSoft} />
              </button>
            </div>
            <div style={{ flex: 1 }}>
              <AInput
                value={lesson.title}
                onChange={(e) => updateLesson(lidx, "title", e.target.value)}
                placeholder="عنوان الدرس"
              />
            </div>
            <div style={{ width: 80 }}>
              <AInput
                type="number"
                value={lesson.durationMin}
                onChange={(e) => updateLesson(lidx, "durationMin", Number(e.target.value))}
                placeholder="دقيقة"
              />
            </div>
            <AButton variant="danger" onClick={() => removeLesson(lidx)}><Trash2 size={13} /></AButton>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
            <div style={{ fontSize: 10.5, fontWeight: 700, color: COLORS.inkSoft }}>فقرات نص الدرس (القراءة الإجبارية)</div>
            {(lesson.body || []).map((para, pidx) => (
              <div key={pidx} style={{ display: "flex", gap: 6, alignItems: "flex-start" }}>
                <ATextarea
                  rows={2}
                  value={para}
                  onChange={(e) => updateLessonParagraph(lidx, pidx, e.target.value)}
                  placeholder={`فقرة ${pidx + 1}`}
                />
                <AButton variant="danger" onClick={() => removeParagraph(lidx, pidx)}><Trash2 size={13} /></AButton>
              </div>
            ))}
            <AButton variant="ghost" onClick={() => addParagraph(lidx)} style={{ alignSelf: "flex-start" }}>
              <Plus size={13} /> إضافة فقرة
            </AButton>
          </div>

          {/* ── Audio section ── */}
          <AdminLessonAudio
            audioUrl={lesson.audioUrl || ""}
            onChange={(url) => updateLesson(lidx, "audioUrl", url)}
          />
        </div>
      ))}

      <div style={{ display: "flex", gap: 8, marginTop: 4 }}>
        <AButton onClick={handleSave} disabled={savingId === draft.id}>
          <Save size={14} /> {savingId === draft.id ? "جارٍ الحفظ..." : "حفظ التغييرات"}
        </AButton>
        <AButton variant="secondary" onClick={handleCancel}>إلغاء</AButton>
      </div>
    </div>
  );


  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <div>
          <div style={{ fontSize: 15, fontWeight: 800, color: COLORS.ink }}>المحاور والدروس</div>
          <div style={{ fontSize: 11.5, color: COLORS.inkSoft, marginTop: 2 }}>
            {modules.length} محور · التعديلات تُحفظ مباشرة وتظهر فورًا للمستضيفين
          </div>
        </div>
        <AButton onClick={addModule}><Plus size={14} /> محور جديد</AButton>
      </div>

      {modules.map((mod) => {
        const isOpen = expandedId === mod.id;
        const tier = TIERS.find((t) => t.id === mod.tier);
        return (
          <ACard key={mod.id}>
            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              <div
                style={{
                  width: 36, height: 36, borderRadius: 10, flexShrink: 0,
                  background: tier ? `${tier.color}1A` : COLORS.sandDeep,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  fontSize: 13, fontWeight: 800, color: tier?.color || COLORS.inkSoft,
                }}
              >
                {mod.id}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 13, fontWeight: 700, color: COLORS.ink }}>{mod.title}</div>
                <div style={{ fontSize: 10.5, color: COLORS.inkSoft, marginTop: 2 }}>
                  {tier?.name || mod.tier} · {mod.lessons.length} دروس · {mod.durationMin} دقيقة
                </div>
              </div>
              <AButton variant="secondary" onClick={() => (isOpen ? handleCancel() : startEdit(mod))}>
                {isOpen ? <ChevronUp size={14} /> : <Pencil size={14} />}
                {isOpen ? "إغلاق" : "تعديل"}
              </AButton>
              <AButton variant="danger" onClick={() => handleDelete(mod)}>
                <Trash2 size={14} />
              </AButton>
            </div>

            {isOpen && draft && renderEditorForm()}
          </ACard>
        );
      })}

      {isNewModule && (
        <ACard style={{ border: `1.5px dashed ${COLORS.teal}` }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div
              style={{
                width: 36, height: 36, borderRadius: 10, flexShrink: 0,
                background: `${COLORS.teal}1A`,
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: 13, fontWeight: 800, color: COLORS.teal,
              }}
            >
              <Plus size={16} />
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 13, fontWeight: 700, color: COLORS.ink }}>محور جديد (غير محفوظ)</div>
              <div style={{ fontSize: 10.5, color: COLORS.inkSoft, marginTop: 2 }}>
                أكمل البيانات أدناه ثم اضغط "حفظ التغييرات" لإضافته
              </div>
            </div>
          </div>
          {renderEditorForm()}
        </ACard>
      )}
    </div>
  );
}


// ---------------------------------------------------------------------------
// Admin: Quizzes editor
// ---------------------------------------------------------------------------
function AdminQuizzesSection({ modules, quizzes, saveQuiz }) {
  const [selectedModuleId, setSelectedModuleId] = useState(modules[0]?.id ?? null);
  const [draft, setDraft] = useState(null);
  const [saving, setSaving] = useState(false);
  const [saveError, setSaveError] = useState("");
  const [saveSuccess, setSaveSuccess] = useState(false);

  useEffect(() => {
    const existing = quizzes[selectedModuleId];
    const mod = modules.find((m) => m.id === selectedModuleId);
    setSaveError("");
    setSaveSuccess(false);
    if (existing) {
      setDraft(JSON.parse(JSON.stringify(existing)));
    } else if (mod) {
      setDraft({ moduleId: selectedModuleId, title: `اختبار: ${mod.title}`, passScore: mod.passScore || 80, questions: [] });
    } else {
      setDraft(null);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedModuleId]);

  if (!draft) {
    return (
      <div style={{ textAlign: "center", padding: 30, color: COLORS.inkSoft, fontSize: 12.5 }}>
        لا توجد محاور بعد. أضف محورًا من تبويب "المحاور والدروس" أولًا.
      </div>
    );
  }

  const clearMessages = () => { setSaveError(""); setSaveSuccess(false); };

  const updateField = (field, value) => { clearMessages(); setDraft((d) => ({ ...d, [field]: value })); };

  const addQuestion = () => {
    clearMessages();
    setDraft((d) => ({
      ...d,
      questions: [...d.questions, { q: "", options: ["", "", "", ""], correct: 0 }],
    }));
  };

  const updateQuestion = (qidx, field, value) => {
    clearMessages();
    setDraft((d) => {
      const questions = [...d.questions];
      questions[qidx] = { ...questions[qidx], [field]: value };
      return { ...d, questions };
    });
  };

  const updateOption = (qidx, oidx, value) => {
    clearMessages();
    setDraft((d) => {
      const questions = [...d.questions];
      const options = [...questions[qidx].options];
      options[oidx] = value;
      questions[qidx] = { ...questions[qidx], options };
      return { ...d, questions };
    });
  };

  const removeQuestion = (qidx) => {
    clearMessages();
    setDraft((d) => ({ ...d, questions: d.questions.filter((_, i) => i !== qidx) }));
  };

  const handleSave = async () => {
    setSaveSuccess(false);
    if (draft.questions.length === 0) {
      setSaveError("يجب إضافة سؤال واحد على الأقل قبل الحفظ.");
      return;
    }
    for (let i = 0; i < draft.questions.length; i++) {
      const q = draft.questions[i];
      if (!q.q.trim()) {
        setSaveError(`السؤال رقم ${i + 1} لا يحتوي على نص.`);
        return;
      }
      const filledOptions = q.options.filter((o) => o.trim());
      if (filledOptions.length < 2) {
        setSaveError(`السؤال رقم ${i + 1} يجب أن يحتوي على خيارين على الأقل.`);
        return;
      }
      if (!q.options[q.correct]?.trim()) {
        setSaveError(`السؤال رقم ${i + 1}: الإجابة الصحيحة المحددة فارغة.`);
        return;
      }
    }
    setSaveError("");
    setSaving(true);
    await saveQuiz(selectedModuleId, draft);
    setSaving(false);
    setSaveSuccess(true);
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      <div>
        <div style={{ fontSize: 15, fontWeight: 800, color: COLORS.ink }}>الاختبارات</div>
        <div style={{ fontSize: 11.5, color: COLORS.inkSoft, marginTop: 2 }}>
          اختر محورًا لإضافة أو تعديل اختبار المحور
        </div>
      </div>

      <AField label="المحور">
        <select dir="rtl" style={inputStyle} value={selectedModuleId} onChange={(e) => setSelectedModuleId(Number(e.target.value))}>
          {modules.map((m) => (
            <option key={m.id} value={m.id}>
              {m.id}. {m.title} {quizzes[m.id] ? "✓ يوجد اختبار" : "— بلا اختبار"}
            </option>
          ))}
        </select>
      </AField>

      <ACard>
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 10 }}>
            <AField label="عنوان الاختبار">
              <AInput value={draft.title} onChange={(e) => updateField("title", e.target.value)} />
            </AField>
            <AField label="نسبة النجاح (%)">
              <AInput type="number" value={draft.passScore} onChange={(e) => updateField("passScore", Number(e.target.value))} />
            </AField>
          </div>

          <div style={{ fontSize: 12.5, fontWeight: 800, color: COLORS.ink, marginTop: 4 }}>
            الأسئلة ({draft.questions.length})
          </div>

          {draft.questions.map((q, qidx) => (
            <div key={qidx} style={{ border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 10, background: COLORS.sand }}>
              <div style={{ display: "flex", gap: 6, alignItems: "flex-start", marginBottom: 8 }}>
                <div style={{ flex: 1 }}>
                  <ATextarea
                    rows={2}
                    value={q.q}
                    onChange={(e) => updateQuestion(qidx, "q", e.target.value)}
                    placeholder={`نص السؤال ${qidx + 1}`}
                  />
                </div>
                <AButton variant="danger" onClick={() => removeQuestion(qidx)}><Trash2 size={13} /></AButton>
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                {q.options.map((opt, oidx) => (
                  <div key={oidx} style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <input
                      type="radio"
                      name={`correct-${qidx}`}
                      checked={q.correct === oidx}
                      onChange={() => updateQuestion(qidx, "correct", oidx)}
                      style={{ flexShrink: 0, width: 16, height: 16, accentColor: COLORS.teal }}
                      title="الإجابة الصحيحة"
                    />
                    <AInput
                      value={opt}
                      onChange={(e) => updateOption(qidx, oidx, e.target.value)}
                      placeholder={`الخيار ${oidx + 1}`}
                    />
                  </div>
                ))}
              </div>
              <div style={{ fontSize: 10, color: COLORS.inkSoft, marginTop: 6 }}>
                حدد الدائرة بجانب الإجابة الصحيحة
              </div>
            </div>
          ))}

          {saveError && (
            <div style={{ fontSize: 12, color: "#C0392B", background: "#C0392B0D", borderRadius: 10, padding: "8px 12px" }}>
              {saveError}
            </div>
          )}
          {saveSuccess && !saveError && (
            <div style={{ fontSize: 12, color: COLORS.teal, background: `${COLORS.teal}0D`, borderRadius: 10, padding: "8px 12px" }}>
              تم حفظ الاختبار بنجاح.
            </div>
          )}

          <div style={{ display: "flex", gap: 8 }}>
            <AButton variant="secondary" onClick={addQuestion}><Plus size={14} /> سؤال جديد</AButton>
            <AButton onClick={handleSave} disabled={saving}>
              <Save size={14} /> {saving ? "جارٍ الحفظ..." : "حفظ الاختبار"}
            </AButton>
          </div>
        </div>
      </ACard>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Admin: Hosts management
// ---------------------------------------------------------------------------
const HOST_STATUS_LABELS = {
  active: { label: "نشط", color: COLORS.teal },
  suspended: { label: "موقوف", color: COLORS.terracotta },
  revoked: { label: "اعتماد مسحوب", color: "#C0392B" },
};

function AdminHostsSection({ hosts, modules, updateHost, reload }) {
  const [search, setSearch] = useState("");
  const [expandedId, setExpandedId] = useState(null);

  const filtered = hosts.filter((h) =>
    h.name.toLowerCase().includes(search.toLowerCase()) ||
    h.email.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <div>
          <div style={{ fontSize: 15, fontWeight: 800, color: COLORS.ink }}>المستضيفون</div>
          <div style={{ fontSize: 11.5, color: COLORS.inkSoft, marginTop: 2 }}>{hosts.length} مستضيف مسجّل</div>
        </div>
        <AButton variant="secondary" onClick={reload}><RotateCcw size={14} /> تحديث</AButton>
      </div>

      <div style={{ position: "relative" }}>
        <Search size={15} color={COLORS.inkSoft} style={{ position: "absolute", right: 12, top: 12 }} />
        <AInput
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="بحث بالاسم أو البريد الإلكتروني"
          style={{ paddingRight: 36 }}
        />
      </div>

      {filtered.map((host) => {
        const isOpen = expandedId === host.id;
        const status = HOST_STATUS_LABELS[host.status] || HOST_STATUS_LABELS.active;
        const overallPct = modules.length
          ? Math.round(
              (modules.reduce((s, m) => s + m.lessons.filter((l) => host.completedLessons.includes(l.id)).length, 0) /
                modules.reduce((s, m) => s + m.lessons.length, 0)) * 100
            )
          : 0;
        const currentTier = TIERS.find((t) => t.id === host.tier) || TIERS[0];

        return (
          <ACard key={host.id}>
            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              <div
                style={{
                  width: 38, height: 38, borderRadius: "50%", flexShrink: 0, background: COLORS.teal,
                  display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontWeight: 800, fontSize: 14,
                }}
              >
                {host.name.charAt(0)}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 13, fontWeight: 700, color: COLORS.ink }}>{host.name}</div>
                <div style={{ fontSize: 10.5, color: COLORS.inkSoft, marginTop: 2 }}>
                  {host.email} · {currentTier.name} · {overallPct}% تقدم
                </div>
              </div>
              <Pill color={status.color} bg={`${status.color}1A`}>{status.label}</Pill>
              <AButton variant="secondary" onClick={() => setExpandedId(isOpen ? null : host.id)}>
                {isOpen ? <ChevronUp size={14} /> : <Pencil size={14} />}
              </AButton>
            </div>

            {isOpen && (
              <div style={{ marginTop: 14, paddingTop: 14, borderTop: `1px solid ${COLORS.line}`, display: "flex", flexDirection: "column", gap: 12 }}>
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10 }}>
                  <div>
                    <div style={{ fontSize: 18, fontWeight: 800, color: COLORS.ink }}>{host.points}</div>
                    <div style={{ fontSize: 10.5, color: COLORS.inkSoft }}>نقاط</div>
                  </div>
                  <div>
                    <div style={{ fontSize: 18, fontWeight: 800, color: COLORS.ink }}>{host.rating ?? "—"}</div>
                    <div style={{ fontSize: 10.5, color: COLORS.inkSoft }}>التقييم</div>
                  </div>
                  <div>
                    <div style={{ fontSize: 18, fontWeight: 800, color: COLORS.ink }}>{host.guestsHosted ?? 0}</div>
                    <div style={{ fontSize: 10.5, color: COLORS.inkSoft }}>عدد الضيوف</div>
                  </div>
                </div>

                <AField label="المستوى الحالي">
                  <select
                    dir="rtl"
                    style={inputStyle}
                    value={host.tier}
                    onChange={(e) => updateHost(host.id, { tier: e.target.value })}
                  >
                    {TIERS.map((t) => <option key={t.id} value={t.id}>{t.name}</option>)}
                  </select>
                </AField>

                <AField label="عدد الضيوف المستضافين (لتتبع شروط الترقية)">
                  <AInput
                    type="number"
                    value={host.guestsHosted ?? 0}
                    onChange={(e) => updateHost(host.id, { guestsHosted: Number(e.target.value) })}
                  />
                </AField>

                <AField label="متوسط التقييم">
                  <AInput
                    type="number"
                    step="0.1"
                    value={host.rating ?? 0}
                    onChange={(e) => updateHost(host.id, { rating: Number(e.target.value) })}
                  />
                </AField>

                <div>
                  <div style={{ fontSize: 11.5, fontWeight: 700, color: COLORS.inkSoft, marginBottom: 6 }}>حالة الاعتماد</div>
                  <div style={{ display: "flex", gap: 8 }}>
                    <AButton
                      variant={host.status === "active" ? "primary" : "secondary"}
                      onClick={() => updateHost(host.id, { status: "active" })}
                    >
                      <CheckCircle2 size={14} /> نشط
                    </AButton>
                    <AButton
                      variant={host.status === "suspended" ? "primary" : "secondary"}
                      onClick={() => updateHost(host.id, { status: "suspended" })}
                    >
                      <PauseCircle size={14} /> إيقاف مؤقت
                    </AButton>
                    <AButton
                      variant={host.status === "revoked" ? "primary" : "danger"}
                      onClick={() => updateHost(host.id, { status: "revoked" })}
                    >
                      <Ban size={14} /> سحب الاعتماد
                    </AButton>
                  </div>
                </div>

                <div>
                  <div style={{ fontSize: 11.5, fontWeight: 700, color: COLORS.inkSoft, marginBottom: 6 }}>
                    التقدم في المحاور ({host.completedLessons.length} درس مكتمل)
                  </div>
                  <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                    {modules.map((mod) => {
                      const pct = moduleProgress(mod, host.completedLessons);
                      return (
                        <div key={mod.id} style={{ display: "flex", alignItems: "center", gap: 8 }}>
                          <div style={{ fontSize: 11, color: COLORS.ink, width: 140, flexShrink: 0 }}>{mod.id}. {mod.title}</div>
                          <div style={{ flex: 1 }}><ProgressBar value={pct} height={5} /></div>
                          <div style={{ fontSize: 10.5, color: COLORS.inkSoft, width: 36, textAlign: "left" }}>{pct}%</div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              </div>
            )}
          </ACard>
        );
      })}

      {filtered.length === 0 && (
        <div style={{ textAlign: "center", padding: 30, color: COLORS.inkSoft, fontSize: 12.5 }}>
          لا توجد نتائج مطابقة
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Admin: Overview
// ---------------------------------------------------------------------------
function AdminOverview({ modules, quizzes, hosts }) {
  const totalLessons = modules.reduce((s, m) => s + m.lessons.length, 0);
  const modulesWithQuiz = modules.filter((m) => quizzes[m.id]).length;
  const activeHosts = hosts.filter((h) => h.status === "active").length;

  const stats = [
    { label: "إجمالي المحاور", value: modules.length, icon: BookOpen },
    { label: "إجمالي الدروس", value: totalLessons, icon: BookOpenCheck },
    { label: "محاور تحتوي اختبارًا", value: `${modulesWithQuiz} / ${modules.length}`, icon: ClipboardCheck },
    { label: "المستضيفون النشطون", value: `${activeHosts} / ${hosts.length}`, icon: Users },
  ];

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <div>
        <div style={{ fontSize: 15, fontWeight: 800, color: COLORS.ink }}>نظرة عامة</div>
        <div style={{ fontSize: 11.5, color: COLORS.inkSoft, marginTop: 2 }}>
          ملخص سريع لحالة محتوى ومستضيفي أكاديمية المستضيف
        </div>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
        {stats.map((s) => (
          <ACard key={s.label}>
            <s.icon size={18} color={COLORS.teal} />
            <div style={{ fontSize: 20, fontWeight: 800, color: COLORS.ink, marginTop: 8 }}>{s.value}</div>
            <div style={{ fontSize: 11, color: COLORS.inkSoft, marginTop: 2 }}>{s.label}</div>
          </ACard>
        ))}
      </div>

      <ACard>
        <div style={{ fontSize: 12.5, fontWeight: 800, color: COLORS.ink, marginBottom: 8 }}>حالة التخزين</div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{ width: 10, height: 10, borderRadius: "50%", background: COLORS.teal }} />
          <div style={{ fontSize: 12, color: COLORS.ink }}>
            متصل بتخزين المنصة — جميع التعديلات تُحفظ وتظهر فورًا لكل المستخدمين
          </div>
        </div>
        <div style={{ fontSize: 11, color: COLORS.inkSoft, marginTop: 8, lineHeight: 1.8 }}>
          يستخدم هذا النموذج تخزين Claude المشترك حاليًا، باستخدام نفس أسماء المجموعات
          (hosts، modules، quizzes) التي ستُستخدم في Firestore عند ربط المنصة بـ Firebase
          الفعلي (بنفس بنية مشروع Muknoon Academy)، بحيث يكون الانتقال مباشرًا دون تعديل
          أي شاشة من شاشات التطبيق.
        </div>
      </ACard>
    </div>
  );
}

