// Admin login gate
// ---------------------------------------------------------------------------
// NOTE: This is a simple client-side credential check suitable for a
// prototype / internal demo. Before going live, replace this with real
// authentication (e.g. Firebase Authentication) so credentials are not
// embedded in client-side code.
const ADMIN_CREDENTIALS = {
  username: "anany2009",
  password: "An5351An$",
};

function AdminLogin({ onSuccess, onCancel }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  const handleSubmit = () => {
    if (username === ADMIN_CREDENTIALS.username && password === ADMIN_CREDENTIALS.password) {
      setError("");
      onSuccess();
    } else {
      setError("اسم المستخدم أو كلمة المرور غير صحيحة");
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      handleSubmit();
    }
  };

  return (
    <div
      dir="rtl"
      style={{
        fontFamily: "'Tahoma', 'Segoe UI', system-ui, sans-serif",
        background: COLORS.sand,
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 18,
      }}
    >
      <div style={{ width: "100%", maxWidth: 360 }}>
        <ACard style={{ display: "flex", flexDirection: "column", gap: 14 }}>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 8, marginBottom: 4 }}>
            <div
              style={{
                width: 48, height: 48, borderRadius: 14, background: COLORS.teal,
                display: "flex", alignItems: "center", justifyContent: "center",
              }}
            >
              <Database size={22} color="#F5E6C8" />
            </div>
            <div style={{ fontSize: 15, fontWeight: 800, color: COLORS.ink }}>تسجيل دخول المشرف</div>
            <div style={{ fontSize: 11.5, color: COLORS.inkSoft, textAlign: "center" }}>
              أكاديمية مستضيفي المدينة المنورة
            </div>
          </div>

          <AField label="اسم المستخدم">
            <AInput
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              onKeyDown={handleKeyDown}
              autoFocus
            />
          </AField>
          <AField label="كلمة المرور">
            <AInput
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              onKeyDown={handleKeyDown}
            />
          </AField>

          {error && (
            <div style={{ fontSize: 12, color: "#C0392B", background: "#C0392B0D", borderRadius: 10, padding: "8px 12px" }}>
              {error}
            </div>
          )}

          <AButton onClick={handleSubmit}><LogOut size={14} style={{ transform: "scaleX(-1)" }} /> تسجيل الدخول</AButton>
          <AButton variant="secondary" onClick={onCancel}>رجوع لواجهة المستضيف</AButton>
        </ACard>
      </div>
    </div>
  );
}

