export default function App() {
  const [mode, setMode] = useState("host"); // "host" | "adminLogin" | "admin"
  const [showSplash, setShowSplash] = useState(true);
  const {
    hostId, checkingSession,
    authBusy, authError, clearError,
    signup, login, logout,
  } = useHostAuth();

  // ── Admin ──────────────────────────────────────────────────────────────────
  if (mode === "adminLogin") {
    return <AdminLogin onSuccess={() => setMode("admin")} onCancel={() => setMode("host")} />;
  }
  if (mode === "admin") {
    return <AdminApp onSwitchToHost={() => setMode("host")} />;
  }

  // ── 1. Splash — always first on every page open ────────────────────────────
  if (showSplash) {
    return (
      <SplashScreen
        onEnter={() => {
          // Clear the active session from state so user must log in again
          // (auth data remains in localStorage so email/password still work)
          logout();
          setShowSplash(false);
        }}
      />
    );
  }

  // ── 2. Checking session ────────────────────────────────────────────────────
  if (checkingSession) {
    return (
      <div dir="rtl" style={{
        fontFamily: "'Tahoma','Segoe UI',system-ui,sans-serif",
        background: "linear-gradient(160deg,#0D2E2C 0%,#1B4D4A 100%)",
        minHeight: "100vh", display: "flex", alignItems: "center",
        justifyContent: "center", flexDirection: "column", gap: 16,
      }}>
        <img src={LOGO_URL} alt="logo" style={{ width: 80, height: 80, objectFit: "contain", opacity: 0.9 }} />
        <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 12 }}>جاري التحقق...</div>
      </div>
    );
  }

  // ── 3. Auth screen — always after splash, login required every time ─────────
  // Even if a session is saved, the user must press "دخول" to enter the app.
  // We show a "متابعة بدون كلمة مرور" option ONLY after successful login.
  if (!hostId) {
    return (
      <HostAuthScreen
        onSignup={signup}
        onLogin={login}
        busy={authBusy}
        error={authError}
        clearError={clearError}
        onSwitchToAdmin={() => setMode("adminLogin")}
      />
    );
  }

  // ── 4. App ─────────────────────────────────────────────────────────────────
  return (
    <HostApp
      hostId={hostId}
      onSwitchToAdmin={() => setMode("adminLogin")}
      onLogout={logout}
    />
  );
}
